      offerInHand: applicantDraft.offerInHand || applicantView.offerInHand || applicantView.offer_in_hand || "",
      lwdOrDoj: applicantDraft.lwdOrDoj || applicantView.lwdOrDoj || applicantView.lwd_or_doj || "",
