  async function saveCapturedAssignment({ recruiterId, jdId, jdTitle, clientName, targetIds = [] }) {
    const isAdmin = String(state.user?.role || "").toLowerCase() === "admin";
    const effectiveRecruiterId = isAdmin ? String(recruiterId || "").trim() : String(state.user?.id || "").trim();
    const recruiter = (state.users || []).find((user) => String(user.id) === String(effectiveRecruiterId));
    const nextAssigneeName = recruiter?.name || state.user?.name || "";
    const ids = (Array.isArray(targetIds) && targetIds.length ? targetIds : [assignCandidateId])
      .map((id) => String(id || "").trim())
      .filter(Boolean);
    const assignAtIso = new Date().toISOString();
    const applyLocalAssignPatch = (candidateId) => {
      const safeCandidateId = String(candidateId || "").trim();
      if (!safeCandidateId) return;
      const applyPatch = (items) => Array.isArray(items)
        ? items.map((item) => {
          if (String(item?.id || "").trim() !== safeCandidateId) return item;
          const next = {
            ...item,
            assigned_to_user_id: effectiveRecruiterId || item?.assigned_to_user_id || "",
            assigned_to_name: nextAssigneeName || item?.assigned_to_name || "",
            assigned_jd_id: String(jdId || "").trim() || item?.assigned_jd_id || "",
            assigned_jd_title: String(jdTitle || "").trim() || item?.assigned_jd_title || "",
            jd_title: String(jdTitle || "").trim() || item?.jd_title || "",
            client_name: String(clientName || "").trim() || item?.client_name || "",
            assigned_at: assignAtIso,
            updated_at: assignAtIso,
            updatedAt: assignAtIso
          };
          if (!String(item?.first_assigned_at || "").trim()) next.first_assigned_at = assignAtIso;
          if (!String(item?.first_assigned_to_user_id || "").trim()) next.first_assigned_to_user_id = effectiveRecruiterId || "";
          if (!String(item?.first_assigned_to_name || "").trim()) next.first_assigned_to_name = nextAssigneeName || "";
          if (!String(item?.first_assigned_by_user_id || "").trim()) next.first_assigned_by_user_id = String(state.user?.id || "").trim();
          if (!String(item?.first_assigned_by_name || "").trim()) next.first_assigned_by_name = String(state.user?.name || "").trim();
          return next;
        })
        : items;
      setState((current) => {
        return {
          ...current,
          candidates: applyPatch(current.candidates),
          databaseCandidates: applyPatch(current.databaseCandidates),
          applicants: applyPatch(current.applicants),
          applicantListItems: applyPatch(current.applicantListItems)
        };
      });
      if (String(location?.pathname || "").trim() === "/captured-notes") {
        setCapturedListItems((current) => applyPatch(current));
        setCapturedOptionPool((current) => applyPatch(current));
      }
    };
    if (isAdmin) {
      const results = await Promise.allSettled(ids.map(async (id) => {
        await api("/candidates/assign", token, "POST", {
          id,
          assignedToUserId: effectiveRecruiterId,
          assignedToName: nextAssigneeName,
          assignedJdId: jdId,
          assignedJdTitle: jdTitle,
          clientName,
          client_name: clientName
        });
        applyLocalAssignPatch(id);
      }));
      const successCount = results.filter((entry) => entry.status === "fulfilled").length;
      const failCount = Math.max(0, ids.length - successCount);
      setAssignCandidateId("");
      setBulkAssignCandidateIds([]);
      setBulkAssignCandidateModalOpen(false);
      if (failCount > 0) {
        setStatus("captured", `${successCount}/${ids.length} drafts assigned. ${failCount} failed, retry once.`, "error");
      } else {
        setStatus("captured", ids.length > 1 ? `${ids.length} drafts assigned to recruiter.` : "Draft assigned to recruiter.", "ok");
      }
      void refreshDashboardAfterAssessmentChange().catch(() => {});
      // Keep reassignment visually stable; local optimistic patch already reflects latest values.
      // Background workspace refresh is intentionally skipped here to avoid full-list flicker.
      return;
    }
    const results = await Promise.allSettled(ids.map(async (id) => {
      await api("/candidates/claim", token, "POST", {
        id,
        assignedJdId: jdId,
        assignedJdTitle: jdTitle,
        jdTitle,
        clientName,
        client_name: clientName
      });
      applyLocalAssignPatch(id);
    }));
    const successCount = results.filter((entry) => entry.status === "fulfilled").length;
    const failCount = Math.max(0, ids.length - successCount);
    setAssignCandidateId("");
    setBulkAssignCandidateIds([]);
    setBulkAssignCandidateModalOpen(false);
    if (failCount > 0) {
      setStatus("captured", `${successCount}/${ids.length} drafts assigned. ${failCount} failed, retry once.`, "error");
    } else {
      setStatus("captured", ids.length > 1 ? `${ids.length} drafts assigned to recruiter.` : "Draft assigned to recruiter.", "ok");
    }
    void refreshDashboardAfterAssessmentChange().catch(() => {});
    // Keep reassignment visually stable; local optimistic patch already reflects latest values.
    // Background workspace refresh is intentionally skipped here to avoid full-list flicker.
  }

  async function patchCandidate(candidateId, patch, okMessage) {
    const currentCandidate = (state.candidates || []).find((item) => String(item.id) === String(candidateId)) || {};
    const nextPatch = { ...patch };
    if (!Object.prototype.hasOwnProperty.call(nextPatch, "draft_payload")) {
      nextPatch.draft_payload = buildCandidateDraftPayloadPatch(currentCandidate, patch);
    }
    if (!Object.prototype.hasOwnProperty.call(nextPatch, "screening_answers")) {
      const currentDraft = getCandidateDraftState(currentCandidate);
      nextPatch.screening_answers = currentDraft.jdScreeningAnswers || parsePortalObjectField(currentCandidate?.screening_answers || currentCandidate?.screeningAnswers);
    }
    await api(`/company/candidates/${encodeURIComponent(candidateId)}`, token, "PATCH", { patch: nextPatch });
    const optimisticUpdatedAt = new Date().toISOString();
    const applyPatch = (items) => Array.isArray(items)
      ? items.map((item) => String(item?.id || "") === String(candidateId) ? { ...item, ...nextPatch, updated_at: optimisticUpdatedAt, updatedAt: optimisticUpdatedAt } : item)
      : items;
    // Optimistic local patch to avoid blocking the UI on a full workspace refresh.
    setState((current) => ({
      ...current,
      candidates: applyPatch(current.candidates),
      databaseCandidates: applyPatch(current.databaseCandidates),
      applicants: applyPatch(current.applicants),
      applicantListItems: applyPatch(current.applicantListItems)
    }));
    if (String(location?.pathname || "").trim() === "/captured-notes") {
      setCapturedListItems((current) => applyPatch(current));
      setCapturedOptionPool((current) => applyPatch(current));
    }
    // No immediate workspace refresh here: optimistic + timestamped local state is source of truth.
    // This avoids delayed viewport jump while preserving correct saved values.
    const liveApplicant = (state.applicantListItems || []).find((item) => String(item?.id || "") === String(candidateId))
      || (state.applicants || []).find((item) => String(item?.id || "") === String(candidateId))
      || null;
    const statusKey = isInboundApplicantSource(liveApplicant?.sourcePlatform || liveApplicant?.source || "")
      ? "applicants"
      : "captured";
    setStatus(statusKey, okMessage, "ok");
  }

  async function patchCandidateQuiet(candidateId, patch, options = {}) {
    const currentCandidate = (state.candidates || []).find((item) => String(item.id) === String(candidateId)) || {};
    const mutationContext = {
      state,
      setState,
      setCapturedOptionPool,
      setCapturedListItems,
      applicantFiltersApplied,
      candidateFiltersApplied,
      applicantSortBy,
      capturedSortBy,
      applicantUser: state.user || null,
      user: state.user || null
    };
    const nextPatch = { ...patch };
    if (!Object.prototype.hasOwnProperty.call(nextPatch, "draft_payload")) {
      nextPatch.draft_payload = buildCandidateDraftPayloadPatch(currentCandidate, patch);
    }
    if (!Object.prototype.hasOwnProperty.call(nextPatch, "screening_answers")) {
      const currentDraft = getCandidateDraftState(currentCandidate);
      nextPatch.screening_answers = currentDraft.jdScreeningAnswers || parsePortalObjectField(currentCandidate?.screening_answers || currentCandidate?.screeningAnswers);
    }
    await api(`/company/candidates/${encodeURIComponent(candidateId)}`, token, "PATCH", { patch: nextPatch });
    const optimisticUpdatedAt = new Date().toISOString();
    await syncPostCandidateMutation({
      candidate: {
        ...currentCandidate,
        ...nextPatch,
        updated_at: optimisticUpdatedAt,
        updatedAt: optimisticUpdatedAt
      },
      candidateId,
      eventType: "candidate_changed",
      source: "MUTATION_SUCCESS",
      refreshList: options?.refreshList === true,
      context: mutationContext
    });
    if (options?.refreshList === true) {
      return;
    }
  }

  async function hideCapturedCandidate(candidateId) {
    if (!String(candidateId || "").trim()) {
      setStatus("captured", "Cannot hide: missing candidate id.", "error");
      return;
    }
    const optimisticUpdatedAt = new Date().toISOString();
    const currentActiveStates = Array.isArray(safeCandidateFiltersApplied.activeStates) && safeCandidateFiltersApplied.activeStates.length
      ? safeCandidateFiltersApplied.activeStates
      : ["Active"];
    const shouldRemainVisible = currentActiveStates.includes("Inactive");
    const patchHiddenState = (items, hidden) => Array.isArray(items)
      ? items.map((item) => String(item?.id || "") === String(candidateId)
        ? { ...item, hidden_from_captured: hidden, updated_at: optimisticUpdatedAt, updatedAt: optimisticUpdatedAt }
        : item)
      : items;
    setCapturedListItems((current) => (shouldRemainVisible
      ? patchHiddenState(current, true)
      : (Array.isArray(current) ? current.filter((item) => String(item?.id || "") !== String(candidateId)) : current)));
    setCapturedOptionPool((current) => patchHiddenState(current, true));
    setState((current) => ({
      ...current,
      candidates: patchHiddenState(current.candidates, true),
      databaseCandidates: patchHiddenState(current.databaseCandidates, true)
    }));
    if (!shouldRemainVisible) {
      setCapturedListMeta((current) => {
        const meta = current && typeof current === "object" ? current : {};
        const nextTotal = Math.max(0, Number(meta.total || 0) - 1);
        const limit = Math.max(1, Number(meta.limit || safeCapturedApiPageSize || 25));
        return {
          ...meta,
          total: nextTotal,
          totalPages: Math.max(1, Math.ceil(nextTotal / limit)),
          page: Math.min(Math.max(1, Number(meta.page || capturedPage || 1)), Math.max(1, Math.ceil(nextTotal / limit))),
          limit
        };
      });
    }
    try {
      await api(`/company/candidates/${encodeURIComponent(candidateId)}`, token, "PATCH", { patch: { hidden_from_captured: true } });
      await refreshCandidateStatsAfterMutation("captured");
      void refreshDashboardAfterAssessmentChange().catch(() => {});
      setStatus("captured", "Candidate hidden from captured notes.", "ok");
    } catch (error) {
      setCapturedListItems((current) => (shouldRemainVisible
        ? patchHiddenState(current, false)
        : (Array.isArray(current) ? current.map((item) => String(item?.id || "") === String(candidateId)
          ? { ...item, hidden_from_captured: false, updated_at: optimisticUpdatedAt, updatedAt: optimisticUpdatedAt }
          : item) : current)));
      setCapturedOptionPool((current) => patchHiddenState(current, false));
      setState((current) => ({
        ...current,
        candidates: patchHiddenState(current.candidates, false),
        databaseCandidates: patchHiddenState(current.databaseCandidates, false)
      }));
      if (!shouldRemainVisible) {
        setCapturedListMeta((current) => {
          const meta = current && typeof current === "object" ? current : {};
          const nextTotal = Math.max(0, Number(meta.total || 0) + 1);
          const limit = Math.max(1, Number(meta.limit || safeCapturedApiPageSize || 25));
          return {
            ...meta,
            total: nextTotal,
            totalPages: Math.max(1, Math.ceil(nextTotal / limit)),
            page: Math.min(Math.max(1, Number(meta.page || capturedPage || 1)), Math.max(1, Math.ceil(nextTotal / limit))),
            limit
          };
        });
      }
      setStatus("captured", String(error?.message || error), "error");
    }
  }

