  async function requestBrandedResumePdfBlob() {
    if (!resumeSampleFile) throw new Error("Select a sample CV first.");
    const isPdf = String(resumeSampleFile.type || "").toLowerCase().includes("pdf") || /\.pdf$/i.test(String(resumeSampleFile.name || ""));
    if (!isPdf) throw new Error("Only PDF sample supports branded export right now.");
    const arr = await resumeSampleFile.arrayBuffer();
    const bytes = new Uint8Array(arr);
    let bin = "";
    for (let i = 0; i < bytes.length; i += 1) bin += String.fromCharCode(bytes[i]);
    const pdfBase64 = window.btoa(bin);
    const candidateName = buildResumeCandidateName(resumeSampleCandidate);
    const candidateMeta = getCandidateProfileCvMeta(resumeSampleCandidate || {});
    const response = await fetch("/company/resume-formatting/branded-pdf", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify({
        pdfBase64,
        filename: String(resumeSampleFile.name || "branded-cv.pdf"),
        candidateId: String(candidateMeta?.candidateId || "").trim(),
        candidateName,
        headerLine: buildResumeHeaderLineForCandidate(resumeSampleCandidate),
        copySettings
      })
    });
    if (!response.ok) {
      const text = await response.text();
      throw new Error(normalizeMojibakeSymbols(text || "Branded PDF generation failed."));
    }
    return response.blob();
  }

  async function openResumeBrandedPreview() {
    try {
      const blob = await requestBrandedResumePdfBlob();
      const url = URL.createObjectURL(blob);
      const candidateName = buildResumeCandidateName(resumeSampleCandidate) || "Candidate";
      const safeName = String(candidateName)
        .replace(/[\\/:*?"<>|]+/g, " ")
        .replace(/\s+/g, " ")
        .trim()
        .replace(/\s+/g, "-");
      const downloadName = `${safeName || "Candidate"}_CV.pdf`;
      const previewTab = window.open("", "_blank");
      if (previewTab && previewTab.document) {
        const safeUrl = String(url).replace(/"/g, "&quot;");
        const safeDownload = String(downloadName).replace(/"/g, "");
        previewTab.document.write(`<!doctype html><html><head><meta charset="utf-8"/><title>Branded CV Preview</title></head><body style="margin:0;font-family:Arial,sans-serif;background:#111827;color:#fff;"><div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:#1f2937;border-bottom:1px solid #374151;"><a href="${safeUrl}" download="${safeDownload}" style="background:#2563eb;color:#fff;text-decoration:none;padding:8px 12px;border-radius:8px;font-weight:600;">Download PDF</a><span style="font-size:13px;color:#cbd5e1;">Preview + Download</span></div><iframe src="${safeUrl}" style="width:100%;height:calc(100vh - 52px);border:0;background:#111827;"></iframe></body></html>`);
        previewTab.document.close();
      } else {
        window.open(url, "_blank", "noopener,noreferrer");
      }
      setTimeout(() => {
        try { URL.revokeObjectURL(url); } catch {}
      }, 120000);
      setStatus("settings", "Branded preview opened.", "ok");
    } catch (error) {
      setStatus("settings", normalizeMojibakeSymbols(String(error?.message || error || "Branded preview failed.")), "error");
    }
  }

  async function downloadBrandedResumePdf() {
    try {
      const blob = await requestBrandedResumePdfBlob();
      const outUrl = URL.createObjectURL(blob);
      const candidateName = buildResumeCandidateName(resumeSampleCandidate) || "Candidate";
      const safeName = String(candidateName)
        .replace(/[\\/:*?"<>|]+/g, " ")
        .replace(/\s+/g, " ")
        .trim()
        .replace(/\s+/g, "-");
      const a = document.createElement("a");
      a.href = outUrl;
      a.download = `${safeName || "Candidate"}_CV.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      setTimeout(() => {
        try { URL.revokeObjectURL(outUrl); } catch {}
      }, 120000);
      setStatus("settings", "Branded PDF generated and downloaded.", "ok");
    } catch (error) {
      setStatus("settings", normalizeMojibakeSymbols(String(error?.message || error || "Branded PDF generation failed.")), "error");
    }
  }

  function replaceClientSharePlaceholdersInHtml(rawHtml, context) {
    let output = String(rawHtml || "");
    const tokens = {
      hr_name: String(context?.hrName || "").trim() || "Team",
      recruiter_name: String(context?.recruiterName || "").trim(),
      recruiter_email: String(context?.recruiterEmail || "").trim(),
      recruiter_phone: String(context?.recruiterPhone || "").trim(),
      company_name: String(context?.companyName || "").trim(),
      client_name: String(context?.clientLabel || "").trim(),
      role: String(context?.targetRole || "").trim(),
      role_line: String(context?.roleLine || "").trim()
    };
    Object.entries(tokens).forEach(([key, value]) => {
      output = output.replace(new RegExp(`\\{\\{\\s*${key}\\s*\\}\\}`, "gi"), escapeHtml(value));
    });
    return output;
  }

  function applyClientJobContentDefaults(nextClientName = "") {
    const clientName = String(nextClientName || "").trim();
    if (!clientName) return;
    const defaults = clientJobContentDefaults[clientName];
    if (!defaults) return;
    setJobDraft((current) => {
      if (String(selectedJobId || current?.id || "").trim()) return current;
      return {
        ...current,
        aboutCompany: String(defaults.aboutCompany || current.aboutCompany || "").trim(),
        publicCompanyLine: String(defaults.publicCompanyLine || current.publicCompanyLine || "").trim(),
        publicTitle: String(defaults.publicTitle || current.publicTitle || "").trim()
      };
    });
  }

  function getClientShareRichBodyHtml() {
    const saved = String(clientShareDraft.richBodyHtml || "").trim();
    if (saved) return saved;
    const isThreadMode = String(clientShareDraft.deliveryMode || "threaded") === "threaded";
    const template = String(
      isThreadMode
        ? (copySettings.clientShareThreadIntroTemplate || DEFAULT_COPY_SETTINGS.clientShareThreadIntroTemplate || "")
        : (copySettings.clientShareIntroTemplate || DEFAULT_COPY_SETTINGS.clientShareIntroTemplate || "")
    ).trim();
    return escapeHtml(template).replace(/\n/g, "<br/>");
  }

  function captureClientShareSelection() {
    try {
      const editor = clientShareEditorRef.current;
      if (!editor) return;
      const selection = window.getSelection?.();
      if (!selection || selection.rangeCount < 1) return;
      const range = selection.getRangeAt(0);
      const anchorNode = selection.anchorNode;
      if (!anchorNode || !editor.contains(anchorNode)) return;
      clientShareSelectionRef.current = range.cloneRange();
    } catch {}
  }

  function restoreClientShareSelection() {
    try {
      const editor = clientShareEditorRef.current;
      const savedRange = clientShareSelectionRef.current;
      if (!editor || !savedRange) return false;
      const selection = window.getSelection?.();
      if (!selection) return false;
      selection.removeAllRanges();
      selection.addRange(savedRange);
      return true;
    } catch {
      return false;
    }
  }

  function syncClientShareEditorHtml() {
    const nextHtml = String(clientShareEditorRef.current?.innerHTML || "").trim();
    clientShareEditorLastHtmlRef.current = nextHtml;
    setClientShareDraft((current) => ({ ...current, richBodyHtml: nextHtml }));
    setClientShareBodyTouched(true);
  }

  function runClientShareEditorCommand(command, value = null) {
    try {
      if (!clientShareEditorRef.current) return;
      clientShareEditorRef.current.focus();
      const restored = restoreClientShareSelection();
      if (!restored) {
        const selection = window.getSelection?.();
        const range = document.createRange();
        range.selectNodeContents(clientShareEditorRef.current);
        range.collapse(false);
        selection?.removeAllRanges();
        selection?.addRange(range);
      }
      document.execCommand(command, false, value);
      captureClientShareSelection();
      syncClientShareEditorHtml();
    } catch {}
  }

  function clearClientShareFormatting() {
    try {
      const editor = clientShareEditorRef.current;
      if (!editor) return;
      editor.focus();
      const selection = window.getSelection?.();
      const hadRange = restoreClientShareSelection();
      if (!hadRange) {
        const range = document.createRange();
        range.selectNodeContents(editor);
        selection?.removeAllRanges();
        selection?.addRange(range);
      }
      document.execCommand("styleWithCSS", false, false);
      document.execCommand("removeFormat", false, null);
      document.execCommand("unlink", false, null);
      captureClientShareSelection();
      syncClientShareEditorHtml();
    } catch {}
  }

  function applyClientShareLink() {
    const raw = window.prompt("Enter link URL");
    const url = String(raw || "").trim();
    if (!url) return;
    const normalized = /^https?:\/\//i.test(url) ? url : `https://${url}`;
    runClientShareEditorCommand("createLink", normalized);
  }

  function looksLikeHtml(value = "") {
    return /<\/?[a-z][\s\S]*>/i.test(String(value || ""));
  }

  function jdDescriptionToEditorHtml(value = "") {
    const raw = String(value || "");
    if (looksLikeHtml(raw)) return raw;
    return escapeHtml(raw).replace(/\n/g, "<br/>");
  }

