  function runJdDescriptionCommand(command, value = null) {
    try {
      const editor = jdDescriptionEditorRef.current;
      if (!editor || jobDraftReadOnly || jobActionBusy) return;
      editor.focus();
      const selection = window.getSelection?.();
      const hasLiveEditorSelection = Boolean(
        selection
        && selection.rangeCount > 0
        && selection.anchorNode
        && editor.contains(selection.anchorNode)
      );
      const restored = hasLiveEditorSelection ? true : restoreJdDescriptionSelection();
      if (!restored) {
        const selection = window.getSelection?.();
        const range = document.createRange();
        range.selectNodeContents(editor);
        range.collapse(false);
        selection?.removeAllRanges();
        selection?.addRange(range);
      }
      const beforeHtml = String(editor.innerHTML || "");
      document.execCommand(command, false, value);
      if (command === "bold") {
        const afterHtml = String(editor.innerHTML || "");
        const sel = window.getSelection?.();
        const range = sel && sel.rangeCount ? sel.getRangeAt(0) : null;
        if (
          beforeHtml === afterHtml
          && range
          && !range.collapsed
          && editor.contains(range.commonAncestorContainer)
        ) {
          const node = document.createElement("strong");
          node.appendChild(range.extractContents());
          range.insertNode(node);
          sel.removeAllRanges();
          const nextRange = document.createRange();
          nextRange.selectNodeContents(node);
          sel.addRange(nextRange);
        }
      }
      captureJdDescriptionSelection();
      syncJdDescriptionEditorHtml();
    } catch {}
  }

  function clearJdDescriptionFormatting() {
    try {
      const editor = jdDescriptionEditorRef.current;
      if (!editor || jobDraftReadOnly || jobActionBusy) return;
      editor.focus();
      const selection = window.getSelection?.();
      const hadRange = restoreJdDescriptionSelection();
      if (!hadRange) {
        const range = document.createRange();
        range.selectNodeContents(editor);
        selection?.removeAllRanges();
        selection?.addRange(range);
      }
      document.execCommand("styleWithCSS", false, false);
      document.execCommand("removeFormat", false, null);
      document.execCommand("unlink", false, null);
      captureJdDescriptionSelection();
      syncJdDescriptionEditorHtml();
    } catch {}
  }

  function applyJdDescriptionLink() {
    const raw = window.prompt("Enter link URL");
    const url = String(raw || "").trim();
    if (!url) return;
    const normalized = /^https?:\/\//i.test(url) ? url : `https://${url}`;
    runJdDescriptionCommand("createLink", normalized);
  }

  function getClientShareSignature() {
    const perUserSignatureHtml = String(smtpSettings.signatureHtml || "").trim();
    const perUserSignatureText = String(smtpSettings.signatureText || "").trim();
    const signatureText = perUserSignatureText;
    const links = [
      {
        label: String(smtpSettings.signatureLinkLabel || "").trim(),
        url: String(smtpSettings.signatureLinkUrl || "").trim()
      },
      {
        label: String(smtpSettings.signatureLinkLabel2 || "").trim(),
        url: String(smtpSettings.signatureLinkUrl2 || "").trim()
      }
    ].filter((link) => link.url);
    return { signatureText, signatureHtml: perUserSignatureHtml, links };
  }

  function splitSignatureLinkLabel(rawLabel) {
    const raw = String(rawLabel || "").trim();
    if (!raw) return { clickLabel: "Link", tail: "" };
    if (/linkedin/i.test(raw)) {
      const tail = raw
        .replace(/linkedin/ig, "")
        .replace(/^[\s|:-]+/, "")
        .replace(/[\s|:-]+$/, "")
        .replace(/\s{2,}/g, " ")
        .trim();
      return { clickLabel: "LinkedIn", tail };
    }
    const [primary, secondary] = raw.split("||");
    const clickLabel = String(primary || raw).trim() || "Link";
    const tail = String(secondary || "").trim();
    return { clickLabel, tail };
  }

  function htmlToPlainText(html) {
    try {
      const container = document.createElement("div");
      container.innerHTML = String(html || "");
      return String(container.textContent || container.innerText || "").trim();
    } catch {
      return String(html || "").replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim();
    }
  }

  function buildClientShareHtml() {
    const rows = getClientShareRows();
    const presetColumns = getClientSharePresetColumns();
    const compactFields = new Set(["s_no", "phone", "email", "current_ctc", "expected_ctc", "notice_period", "total_experience"]);
    const wideFields = new Set(["screening_remarks", "reason_of_change", "remarks", "other_standard_questions", "linkedin"]);
    const tableColGroup = presetColumns.map((column) => {
      const key = String(column?.field || "").trim().toLowerCase();
      const width = compactFields.has(key) ? "120px" : (wideFields.has(key) ? "220px" : "170px");
      return `<col style="width:${width};min-width:${width};" />`;
    }).join("");
    const tableHeaders = presetColumns.map((column) => `<th style="border:1px solid #d8dee8;padding:10px 12px;background:#f6f8fb;text-align:left;font-size:13px;">${escapeHtml(column.header)}</th>`).join("");
    const tableRows = rows.map((item, index) => {
      const cells = presetColumns.map((column) => {
        const value = getCapturedExportFieldValue({ index: index + 1, ...item }, column.field) || "-";
        return `<td style="border:1px solid #d8dee8;padding:10px 12px;vertical-align:top;font-size:13px;line-height:1.45;white-space:normal;word-break:break-word;overflow-wrap:anywhere;">${escapeHtml(value).replace(/\n/g, "<br/>")}</td>`;
      }).join("");
      const shareKey = String(item.candidate_id || item.id || "");
      const cvLink = clientShareCvLinks[shareKey];
      const cvCell = cvLink
        ? `<a href="${escapeHtml(cvLink)}" target="_blank" rel="noopener noreferrer" style="color:#0b57d0;text-decoration:none;">Open CV</a>`
        : (!shareKey
          ? "Linked candidate not found"
          : (clientShareCvLinkState[shareKey] === "missing" ? "CV link not available yet" : "Generating secure CV link..."));
      return `<tr>${cells}<td style="border:1px solid #d8dee8;padding:10px 12px;vertical-align:top;font-size:13px;line-height:1.45;white-space:normal;word-break:break-word;overflow-wrap:anywhere;">${cvCell}</td></tr>`;
    }).join("");
    const isThreadMode = String(clientShareDraft.deliveryMode || "threaded") === "threaded";
    const template = String(
      isThreadMode
        ? (copySettings.clientShareThreadIntroTemplate || DEFAULT_COPY_SETTINGS.clientShareThreadIntroTemplate || "")
        : (copySettings.clientShareIntroTemplate || DEFAULT_COPY_SETTINGS.clientShareIntroTemplate || "")
    ).trim();
    const introHtml = replaceClientSharePlaceholdersInHtml(escapeHtml(template).replace(/\n/g, "<br/>"), getClientShareContext());
    const signature = getClientShareSignature();
    const signatureLinksHtml = signature.links
      .map((link) => {
        const parts = splitSignatureLinkLabel(link.label || link.url || "");
        const clickLabel = parts.clickLabel;
        const tail = parts.tail;
        const anchor = `<a href="${escapeHtml(link.url)}" target="_blank" rel="noopener noreferrer" style="color:#0b57d0;text-decoration:none;">${escapeHtml(clickLabel || link.url)}</a>`;
        return tail ? `${anchor} ${escapeHtml(tail)}` : anchor;
      })
      .join("<br/>");
    const signatureHtml = String(signature.signatureHtml || "").trim()
      || [
        signature.signatureText ? escapeHtml(signature.signatureText).replace(/\n/g, "<br/>") : "",
        signatureLinksHtml
      ].filter(Boolean).join("<br/>");
    const signatureHtmlFinal = [
      signatureHtml,
      signatureLinksHtml && !/<a\b/i.test(signatureHtml) ? `<div style="margin-top:6px;">${signatureLinksHtml}</div>` : ""
    ].filter(Boolean).join("");
    return `
      <div style="font-family:Arial, sans-serif;color:#1f2a44;line-height:1.6;">
        <div>${introHtml}</div>
        <p>${rows.length} selected profile(s) are listed below.</p>
        <table style="border-collapse:collapse;width:100%;margin-top:12px;table-layout:fixed;">
          <colgroup>${tableColGroup}<col style="width:110px;min-width:110px;" /></colgroup>
          <thead>
            <tr>${tableHeaders}<th style="border:1px solid #d8dee8;padding:10px 12px;background:#f6f8fb;text-align:left;font-size:13px;">CV Link</th></tr>
          </thead>
          <tbody>
            ${tableRows}
          </tbody>
        </table>
        ${signatureHtmlFinal ? `<div style="margin-top:18px;">${signatureHtmlFinal}</div>` : ""}
      </div>
    `.trim();
  }

  function getClientShareComposedHtml() {
    try {
      const liveEditorHtml = String(clientShareEditorRef.current?.innerHTML || "").trim();
      if (clientShareBodyTouched && liveEditorHtml) return liveEditorHtml;
    } catch {}
    const saved = String(clientShareDraft.richBodyHtml || "").trim();
    if (clientShareBodyTouched && saved) return saved;
    return buildClientShareHtml();
  }

  function getClientShareComposedText() {
    return htmlToPlainText(getClientShareComposedHtml());
  }

  function getClientShareEmailSubject() {
    const context = getClientShareContext();
    const explicit = String(clientShareDraft.emailSubject || "").trim();
    if (explicit) return fillClientShareTemplate(explicit, context).trim();
    const subjectTemplate = String(copySettings.clientShareSubjectTemplate || DEFAULT_COPY_SETTINGS.clientShareSubjectTemplate || "").trim();
    if (subjectTemplate) {
      const rendered = fillClientShareTemplate(subjectTemplate, context).trim();
      if (rendered) return rendered;
    }
    const companyName = String(context.clientLabel || "").trim();
    const roleLine = String(context.targetRole || context.roleLine || "").trim();
    if (companyName && roleLine) return `${companyName} - Candidate Profiles for ${roleLine}`;
    if (companyName) return `${companyName} - Candidate Profiles`;
    if (roleLine) return `Candidate Profiles for ${roleLine}`;
    return "Candidate Profiles";
  }

  function getClientShareSendHtml() {
    const composed = String(getClientShareComposedHtml() || "").trim();
    const plain = htmlToPlainText(composed);
    const hasTable = /<table[\s>]/i.test(composed);
    if (!composed || plain.length < 20) return buildClientShareHtml();
    if (!hasTable) return buildClientShareHtml();
    return composed;
  }

  async function dispatchClientShareEmail(payload) {
    const to = String(payload?.to || "").trim();
    const cc = String(payload?.cc || "").trim();
    const subject = String(payload?.subject || "").trim();
    const html = String(payload?.html || "").trim();
    const text = String(payload?.text || "").trim();
    const cvAttachments = Array.isArray(payload?.cvAttachments) ? payload.cvAttachments : [];
    const result = await api("/company/email/send", token, "POST", {
      to,
      cc,
      subject,
      html,
      text,
      cvAttachments,
      forceNewThread: Boolean(payload?.forceNewThread),
      threadContext: {
        clientLabel: String(clientShareDraft.clientLabel || "").trim(),
        role: String(clientShareDraft.targetRole || "").trim()
      }
    });
    setDirectShareHistory((current) => ({
      to: uniqueEmails([to, ...(current.to || [])]).slice(0, 40),
      cc: uniqueEmails([...(cc ? parseEmailTokens(cc) : []), ...(current.cc || [])]).slice(0, 60)
    }));
    return result;
  }

  function clearClientShareQueueTimers() {
    if (clientShareQueueTimeoutRef.current) {
      clearTimeout(clientShareQueueTimeoutRef.current);
      clientShareQueueTimeoutRef.current = null;
    }
    if (clientShareQueueIntervalRef.current) {
      clearInterval(clientShareQueueIntervalRef.current);
      clientShareQueueIntervalRef.current = null;
    }
  }

  function cancelQueuedClientShareEmail() {
    clearClientShareQueueTimers();
    clientShareQueuePayloadRef.current = null;
    setClientShareSendQueue({ pending: false, executeAt: 0, to: "", subject: "" });
    setClientShareQueueSeconds(0);
    setStatus("clientShare", "Send cancelled before dispatch.", "ok");
  }

  async function flushQueuedClientShareEmail() {
    const payload = clientShareQueuePayloadRef.current;
    clearClientShareQueueTimers();
    setClientShareSendQueue({ pending: false, executeAt: 0, to: "", subject: "" });
    setClientShareQueueSeconds(0);
    clientShareQueuePayloadRef.current = null;
    if (!payload) return;
    try {
      setStatus("clientShare", "Sending email...", "ok");
      const result = await dispatchClientShareEmail(payload);
      const isThreaded = Boolean(result?.threaded);
      setStatus(
        "clientShare",
        isThreaded
          ? "Email sent in existing mail chain. Check your Sent folder to confirm."
          : "Email sent as a new thread. Check your Sent folder to confirm.",
        "ok"
      );
    } catch (error) {
      setStatus("clientShare", `Email failed: ${String(error?.message || error)}`, "error");
    }
  }

  function queueClientShareEmail(payload) {
    clearClientShareQueueTimers();
    clientShareQueuePayloadRef.current = payload;
    const executeAt = Date.now() + 10000;
    setClientShareSendQueue({
      pending: true,
      executeAt,
      to: String(payload?.to || ""),
      subject: String(payload?.subject || "")
    });
    setClientShareQueueSeconds(10);
    clientShareQueueIntervalRef.current = setInterval(() => {
      const seconds = Math.max(0, Math.ceil((executeAt - Date.now()) / 1000));
      setClientShareQueueSeconds(seconds);
    }, 250);
    clientShareQueueTimeoutRef.current = setTimeout(() => {
      void flushQueuedClientShareEmail();
    }, 10000);
    setStatus("clientShare", "Email queued. You can undo within 10 seconds.", "ok");
  }

  async function sendClientShareEmail() {
    if (!getClientShareRows().length) {
      setStatus("clientShare", "Select assessment profiles first from the Assessments tab.", "error");
      return;
    }
    const to = String(clientShareDraft.recipientEmail || "").trim();
    const cc = uniqueEmails(parseEmailTokens(clientShareDraft.ccEmails || "")).join(", ");
    if (!to) {
      setStatus("clientShare", "Recipient email is required.", "error");
      return;
    }
    const sendHtml = getClientShareSendHtml();
    const cvAttachments = getClientShareRows()
      .map((item) => {
        const shareKey = String(item.candidate_id || item.id || "");
        const signedUrl = String(clientShareCvLinks[shareKey] || "").trim();
        const provider = String(item.cv_provider || "").trim();
        const key = String(item.cv_key || "").trim();
        const directUrl = String(item.cv_url || "").trim();
        const filename = String(item.cv_filename || "").trim();
        if (!signedUrl && !key && !directUrl) return null;
        return {
          candidateId: String(item.candidate_id || "").trim(),
          signedUrl,
          provider,
          key,
          url: directUrl,
          filename,
          mimeType: ""
        };
      })
      .filter(Boolean);
    queueClientShareEmail({
      to,
      cc,
      subject: getClientShareEmailSubject(),
      html: sendHtml,
      text: htmlToPlainText(sendHtml),
      cvAttachments,
      forceNewThread: String(clientShareDraft.deliveryMode || "threaded") === "new"
    });
  }

  async function copyClientShareEmailDraft() {
    if (!getClientShareRows().length) {
      setStatus("clientShare", "Select assessment profiles first from the Assessments tab.", "error");
      return;
    }
    await copyHtmlAndText(getClientShareComposedHtml(), getClientShareComposedText());
    setStatus("clientShare", "Client email draft copied in table format.", "ok");
  }

  async function copyClientShareTracker() {
    const rows = getClientShareRows();
    if (!rows.length) {
      setStatus("clientShare", "Select assessment profiles first from the Assessments tab.", "error");
      return;
    }
    const rowsWithCv = rows.map((item, index) => ({
      ...item,
      index: index + 1,
      s_no: index + 1,
      cv_link: getClientShareCvText(item),
      cv_url: getClientShareCvText(item)
    }));
    const preset = buildCapturedExcelRows(rowsWithCv, clientShareDraft.presetId || copySettings.excelPreset, copySettings);
    const hasCvColumn = preset.headers.some((header) => String(header || "").trim().toLowerCase().includes("cv"));
    const headers = hasCvColumn ? preset.headers : [...preset.headers, "CV Link"];
    const outputRows = preset.rows.map((row, index) => (hasCvColumn
      ? row
      : [...row, getCapturedExportFieldValue({ cv_link: getClientShareCvText(rows[index] || {}) }, "cv_link")]
    ));
    const lines = [
      headers.join("\t"),
      ...outputRows.map((row) => row.map((cell) => normalizeExcelClipboardCell(cell)).join("\t"))
    ].join("\n");
    await copyText(lines);
    setStatus("clientShare", "Selected profiles copied as tracker in the chosen preset.", "ok");
  }

  async function toggleAssessmentSelectionWithBranding(assessment = {}) {
    const id = String(assessment?.id || "").trim();
    if (!id) return;
    const currentlySelected = selectedAssessmentIds.includes(id);
    if (currentlySelected) {
      setSelectedAssessmentIds((current) => current.filter((item) => item !== id));
      if (isAssessmentShareBrandedCvEnabled(assessment)) {
        await setAssessmentShareBrandedCv(assessment, false);
      }
      return;
    }
    setSelectedAssessmentIds((current) => (current.includes(id) ? current : [...current, id]));
  }

  function isAssessmentShareBrandedCvEnabled(assessment = {}) {
    return Boolean(
      assessment?.shareBrandedCv
      || assessment?.share_branded_cv
      || assessment?.payload?.shareBrandedCv
      || assessment?.payload?.share_branded_cv
    );
  }

  async function setAssessmentShareBrandedCv(assessment, enabled) {
    const current = assessment && typeof assessment === "object" ? assessment : null;
    const assessmentId = String(current?.id || "").trim();
    if (!assessmentId) return;
    const nextShareBrandedCv = Boolean(enabled);
    const patchVisibleAssessmentShareState = (currentRow, rowEnabled) => {
      if (!currentRow || typeof currentRow !== "object") return currentRow;
      return {
        ...currentRow,
        shareBrandedCv: Boolean(rowEnabled),
        share_branded_cv: Boolean(rowEnabled),
        payload: {
          ...((currentRow && currentRow.payload && typeof currentRow.payload === "object") ? currentRow.payload : {}),
          shareBrandedCv: Boolean(rowEnabled),
          share_branded_cv: Boolean(rowEnabled)
        }
      };
    };
    // Optimistic UI: reflect checkbox state immediately.
    applyAssessmentChange({
      type: "PATCH_ROW",
      scope: "all",
      assessment: patchVisibleAssessmentShareState(current, nextShareBrandedCv),
      source: "LOCAL_PATCH"
    });
    try {
      const next = {
        ...current,
        shareBrandedCv: nextShareBrandedCv,
        share_branded_cv: nextShareBrandedCv,
        preserveUpdatedAt: true,
        payload: {
          ...((current && current.payload && typeof current.payload === "object") ? current.payload : {}),
          shareBrandedCv: nextShareBrandedCv,
          share_branded_cv: nextShareBrandedCv
        },
        updatedAt: String(current?.updatedAt || current?.updated_at || "").trim()
      };
      const saved = await api("/company/assessments", token, "POST", { assessment: next });
      const savedId = String(saved?.id || assessmentId).trim();
      applyAssessmentChange({
        type: "PATCH_ROW",
        scope: "all",
        assessment: saved || {
          ...current,
          ...next,
          shareBrandedCv: Boolean(saved?.shareBrandedCv ?? saved?.share_branded_cv ?? nextShareBrandedCv),
          share_branded_cv: Boolean(saved?.share_branded_cv ?? saved?.shareBrandedCv ?? nextShareBrandedCv)
        },
        source: "MUTATION_SUCCESS"
      });
      setStatus("assessments", enabled ? "Share Branded CV enabled for this profile." : "Share Branded CV disabled for this profile.", "ok");
    } catch (error) {
      // Revert optimistic toggle on failure.
      applyAssessmentChange({
        type: "PATCH_ROW",
        scope: "all",
        assessment: patchVisibleAssessmentShareState(current, !nextShareBrandedCv),
        source: "LOCAL_PATCH"
      });
      setStatus("assessments", String(error?.message || error || "Could not update branded CV preference."), "error");
    }
  }

  async function saveSharedCopySettings() {
    if (!isSettingsAdmin) {
      setStatus("settings", "Only admin can save shared settings.", "error");
      return;
    }
    const draftSettings = {
      ...copySettings,
      exportPresetLabels: copySettings.exportPresetLabels || DEFAULT_COPY_SETTINGS.exportPresetLabels,
      exportPresetClientMap: copySettings.exportPresetClientMap || DEFAULT_COPY_SETTINGS.exportPresetClientMap,
      customExportPresets: copySettings.customExportPresets || []
    };
    const existingLogo = String(draftSettings?.resumeFormatting?.logoDataUrl || "").trim();
    if (existingLogo && !isPdfEmbeddableLogoDataUrl(existingLogo)) {
      try {
        const pngDataUrl = await convertLogoDataUrlToPng(existingLogo);
        draftSettings.resumeFormatting = {
          ...(draftSettings.resumeFormatting || {}),
          logoDataUrl: pngDataUrl
        };
        setCopySettings((current) => ({
          ...current,
          resumeFormatting: {
            ...(current.resumeFormatting || {}),
            logoDataUrl: pngDataUrl
          }
        }));
      } catch {
        setStatus("settings", "Saved logo format is not PDF-compatible. Please re-upload logo as PNG or JPG.", "error");
        return;
      }
    }
    const payload = migrateCopySettings(draftSettings);
    const result = await api("/company/shared-export-presets", token, "POST", {
      settings: payload,
      saveAsSuggestedGlobal: Boolean(isSuggestedPresetSelected && canPublishSuggestedGlobalPresets)
    });
    setCopySettings((current) => ({ ...DEFAULT_COPY_SETTINGS, ...current, ...result }));
    setStatus("settings", "Shared copy presets saved for all recruiters.", "ok");
  }

