function buildJourneyText(assessment, contactAttempts = [], candidate = null) {
    const header = [
      assessment?.candidateName || "Candidate",
      assessment?.jdTitle ? `JD: ${assessment.jdTitle}` : "",
      assessment?.candidateStatus ? `Current status: ${assessment.candidateStatus}` : ""
    ].filter(Boolean);
    const timeline = buildAssessmentJourneyEntries(assessment, contactAttempts, candidate)
      .map((item) => `${new Date(item.at).toLocaleString()} | ${item.text}`);
    return [...header, "", "Journey:", ...timeline].filter(Boolean).join("\n");
  }

  async function saveAssessmentStatusUpdate(assessment, payload, options = {}) {
    const statusTarget = options.statusTarget || "assessments";
    const lockKey = String(assessment?.id || assessment?.candidateId || "").trim();
    if (lockKey && assessmentStatusSaveLockRef.current.has(lockKey)) {
      setStatus(statusTarget, "Status update already in progress for this candidate.", "error");
      return;
    }
    if (lockKey) assessmentStatusSaveLockRef.current.add(lockKey);
    try {
    const inferText = String(payload?.inferText || payload?.notes || "").trim();
    const manualRemarks = String(payload?.manualRemarks || "").trim();
    const combinedNotes = [inferText, manualRemarks ? `Remarks: ${manualRemarks}` : ""].filter(Boolean).join("\n");
    const lastLine = extractLastMeaningfulLine(inferText);
    const inferred = inferAssessmentStatusAndSchedule(lastLine);
    // Keep recruiter's explicit status selection as source of truth.
    // Infer box should assist, not override a deliberate dropdown choice.
    let nextStatus = String(payload?.candidateStatus || inferred.candidateStatus || "").trim();
    if (!nextStatus) throw new Error("Select a status first.");
    const hasAlignedInHistory = (() => {
      const current = String(normalizeAssessmentStatusLabel(assessment?.candidateStatus || "") || "").toLowerCase();
      if (isInterviewAlignedStatus(current)) return true;
      const history = Array.isArray(assessment?.statusHistory) ? assessment.statusHistory : [];
      return history.some((entry) => isInterviewAlignedStatus(entry?.status || ""));
    })();
    if (String(nextStatus || "").trim().toLowerCase() === "feedback awaited") {
      nextStatus = hasAlignedInHistory ? "Interview feedback awaited" : "CV feedback awaited";
    }
    if (String(nextStatus || "").trim().toLowerCase() === "hold") {
      nextStatus = hasAlignedInHistory ? "Interview On Hold" : "CV put on hold";
    }
    const nextStatusLower = nextStatus.toLowerCase();
    const isInterviewStatus = isInterviewAlignedStatus(nextStatus);
    const isOffered = nextStatusLower === "offered";
    const isJoined = nextStatusLower === "joined";
    // Calendar picker should always win over stale infer-box text when the user explicitly changes date/time.
    // (Infer box still works because we keep it synced into atValue via the modal effect.)
    const effectiveAtValue = isOffered
      ? (payload?.expectedDoj || payload?.atValue || inferred.expectedDoj || inferred.atValue || "")
      : isJoined
        ? (payload?.dateOfJoining || payload?.atValue || inferred.dateOfJoining || inferred.atValue || "")
        : (payload?.atValue || inferred.atValue || "");
    const dateCandidate = effectiveAtValue ? new Date(effectiveAtValue) : null;
    const atIso = (isInterviewStatus || isOffered || isJoined) && dateCandidate && !Number.isNaN(dateCandidate.getTime())
      ? dateCandidate.toISOString()
      : "";
    const readableNotes = formatReadableUpdateText(combinedNotes);
    const confirmMessage = buildDetectedUpdateConfirmation({
      candidateName: assessment?.candidateName || "",
      status: nextStatus,
      interviewAt: isInterviewStatus ? atIso : "",
      followUpAt: !isInterviewStatus && (isOffered || isJoined) ? atIso : "",
      notes: [
        readableNotes,
        buildAssessmentStatusNoteLine(nextStatus, atIso, { offerAmount: payload?.offerAmount })
      ].filter(Boolean).join("\n")
    });
    if (!window.confirm(confirmMessage)) return;

    const nextAssessment = {
      ...assessment,
      candidateStatus: nextStatus,
      pipelineStage: mapAssessmentStatusToPipelineStage(nextStatus) || assessment?.pipelineStage || "",
      callbackNotes: appendReadableUpdateNote(
        assessment?.callbackNotes || "",
        [readableNotes, buildAssessmentStatusNoteLine(nextStatus, atIso, { offerAmount: payload?.offerAmount })].filter(Boolean).join("\n")
      ),
      interviewAttempts: Array.isArray(assessment?.interviewAttempts) ? [...assessment.interviewAttempts] : [],
      statusHistory: Array.isArray(assessment?.statusHistory) ? [...assessment.statusHistory] : [],
      offerAmount: (isOffered || isJoined) ? String(payload?.offerAmount || inferred.offerAmount || assessment?.offerAmount || "").trim() : (assessment?.offerAmount || ""),
      offerDoj: (isOffered || isJoined) ? atIso : (assessment?.offerDoj || assessment?.offer_doj || ""),
      lwdOrDoj: (isOffered || isJoined) ? atIso : (assessment?.lwdOrDoj || assessment?.lwd_or_doj || assessment?.offerDoj || assessment?.offer_doj || ""),
      expectedDoj: isOffered ? atIso : (assessment?.expectedDoj || ""),
      dateOfJoining: isJoined ? atIso : (assessment?.dateOfJoining || ""),
      updatedAt: new Date().toISOString()
    };
    const expectedUpdatedAt = String(assessment?.updatedAt || assessment?.updated_at || "").trim();
    const statusUpdatedAt = new Date().toISOString();
    nextAssessment.statusHistory.push({
      status: nextStatus,
      at: statusUpdatedAt,
      statusAt: atIso || "",
      notes: readableNotes || "",
      inferText,
      manualRemarks,
      offerAmount: (isOffered || isJoined) ? String(payload?.offerAmount || inferred.offerAmount || assessment?.offerAmount || "").trim() : "",
      atLabel: buildAssessmentStatusNoteLine(nextStatus, atIso, { offerAmount: payload?.offerAmount })
    });

    if (isInterviewStatus) {
      nextAssessment.interviewAttempts.push({
        round: deriveInterviewRoundFromStatus(nextStatus) || "Interview",
        outcome: "Scheduled",
        at: statusUpdatedAt,
        notes: readableNotes || nextStatus,
        createdAt: statusUpdatedAt
      });
    } else if (nextStatusLower === "not responding" || nextStatusLower === "did not attend") {
      nextAssessment.interviewAttempts.push({
        round: deriveInterviewRoundFromStatus(nextStatus) || "Interview",
        outcome: "Not responding",
        at: new Date().toISOString(),
        notes: readableNotes || nextStatus,
        createdAt: new Date().toISOString()
      });
    } else if (nextStatusLower === "interview reject") {
      nextAssessment.interviewAttempts.push({
        round: "Interview",
        outcome: "Rejected",
        at: new Date().toISOString(),
        notes: readableNotes || nextStatus,
        createdAt: new Date().toISOString()
      });
    }

    nextAssessment.interviewAt = isInterviewStatus ? (atIso || assessment?.interviewAt || "") : "";
    nextAssessment.followUpAt = !isInterviewStatus && (isOffered || isJoined) ? atIso : "";
    if (options.clearAgendaSchedule) {
      nextAssessment.interviewAt = "";
      nextAssessment.followUpAt = "";
    }

    const linkedCandidateId = String(assessment?.candidateId || "").trim();
    const currentCandidate = linkedCandidateId
      ? ((state.candidates || []).find((item) => String(item.id || "") === linkedCandidateId) || {})
      : {};
    let candidatePatch = null;
    let nextDraftPayload = null;
    let nextScreeningAnswers = null;
    if (linkedCandidateId) {
      candidatePatch = {
        assessment_status: nextStatus,
        company: String(nextAssessment?.currentCompany || "").trim(),
        role: String(nextAssessment?.currentDesignation || "").trim(),
        experience: String(nextAssessment?.totalExperience || "").trim(),
        current_ctc: String(nextAssessment?.currentCtc || "").trim(),
        expected_ctc: String(nextAssessment?.expectedCtc || "").trim(),
        notice_period: String(nextAssessment?.noticePeriod || "").trim(),
        recruiter_context_notes: String(nextAssessment?.recruiterNotes || "").trim(),
        other_pointers: String(nextAssessment?.otherPointers || "").trim(),
        notes: appendReadableUpdateNote(
          currentCandidate?.notes || "",
          [readableNotes, buildAssessmentStatusNoteLine(nextStatus, atIso, { offerAmount: payload?.offerAmount })].filter(Boolean).join("\n")
        )
      };
      if (isInterviewStatus || isOffered || isJoined) {
        candidatePatch.next_follow_up_at = atIso || "";
      }
      nextDraftPayload = buildCandidateDraftPayloadPatch(currentCandidate, {
        candidateStatus: nextStatus,
        callbackNotes: candidatePatch.notes,
        followUpAt: candidatePatch.next_follow_up_at,
        interviewAt: isInterviewStatus ? (atIso || "") : "",
        statusHistory: Array.isArray(nextAssessment.statusHistory) ? nextAssessment.statusHistory : [],
        pipelineStage: nextAssessment.pipelineStage
      });
      const currentDraft = getCandidateDraftState(currentCandidate);
      nextScreeningAnswers = currentDraft.jdScreeningAnswers || parsePortalObjectField(currentCandidate?.screening_answers || currentCandidate?.screeningAnswers);
    }

    // Optimistic UI first: reflect status immediately everywhere.
    applyAssessmentChange({
      type: "STATUS_UPDATE",
      scope: "all",
      assessment: nextAssessment,
      source: "LOCAL_PATCH"
    });
    if (candidatePatch && linkedCandidateId) {
      const optimisticUpdatedAt = new Date().toISOString();
      setState((current) => {
        const applyPatch = (items) => Array.isArray(items)
          ? items.map((item) => String(item?.id || "") === linkedCandidateId
            ? { ...item, ...candidatePatch, draft_payload: nextDraftPayload, updated_at: optimisticUpdatedAt, updatedAt: optimisticUpdatedAt }
            : item)
          : items;
        return {
          ...current,
          candidates: applyPatch(current.candidates),
          databaseCandidates: applyPatch(current.databaseCandidates)
        };
      });
    }
    setStatus(statusTarget, `Updated status for ${assessment?.candidateName || "candidate"}.`, "ok");
    if (options.closeModal !== false) setAssessmentStatusId("");

    // Persist in background; if fails, surface error and refresh to resync.
    void (async () => {
      try {
        await api("/company/assessments", token, "POST", {
          assessment: {
            ...nextAssessment,
            expectedUpdatedAt,
            generatedAt: assessment?.generatedAt || new Date().toISOString()
          }
        });
        applyAssessmentChange({
          type: "STATUS_UPDATE",
          scope: "all",
          assessment: nextAssessment,
          source: "MUTATION_SUCCESS"
        });
        if (linkedCandidateId && candidatePatch) {
          await api(`/company/candidates/${encodeURIComponent(linkedCandidateId)}`, token, "PATCH", {
            patch: {
              ...candidatePatch,
              draft_payload: nextDraftPayload,
              screening_answers: nextScreeningAnswers
            }
          });
        }
        void syncPostAssessmentMutation({ candidateId: linkedCandidateId }).catch(() => {});
        void refreshDashboardAfterAssessmentChange().catch(() => {});
        // Skip immediate workspace refresh to keep viewport stable after status update.
      } catch (error) {
        setStatus(statusTarget, `Status sync failed: ${String(error?.message || error)}`, "error");
        void refreshAssessmentFallback({ candidateId: linkedCandidateId }).catch(() => {});
      }
    })();
    } finally {
      if (lockKey) {
        window.setTimeout(() => {
          assessmentStatusSaveLockRef.current.delete(lockKey);
        }, 1500);
      }
    }
  }

  async function deleteAssessmentItem(assessment) {
    if (!window.confirm(`Delete assessment for ${assessment?.candidateName || "candidate"}?`)) return;
    await api("/company/assessments", token, "DELETE", { assessmentId: assessment?.id });
    applyAssessmentChange({
      type: "DELETE_ROW",
      scope: "all",
      assessmentId: assessment?.id,
      source: "MUTATION_SUCCESS",
      refreshStats: true
    });
    void syncPostAssessmentMutation({ candidateId: assessment?.candidateId }).catch(() => {});
    void refreshDashboardAfterAssessmentChange().catch(() => {});
    setStatus("assessments", "Assessment deleted.", "ok");
  }

  function upsertAssessmentInState(saved) {
    applyAssessmentChange({
      type: "UPSERT_ROW",
      scope: "backing",
      assessment: saved,
      source: "MUTATION_SUCCESS"
    });
  }

  function applyAssessmentChange(change = {}) {
    const type = String(change?.type || change?.action || "").trim().toUpperCase();
    const scope = String(change?.scope || "visible").trim().toLowerCase() || "visible";
    const assessment = change?.assessment && typeof change.assessment === "object" ? change.assessment : null;
    const assessmentId = String(change?.assessmentId || assessment?.id || "").trim();
    if (!assessmentId && type !== "RELOAD_SLICE") return;

    if (typeof console !== "undefined" && typeof console.debug === "function") {
      console.debug("[assessment-change]", {
        source: String(change?.source || "LOCAL_PATCH").trim() || "LOCAL_PATCH",
        type,
        scope,
        assessmentId
      });
    }

    const linkedCandidate = assessment
      ? resolveAssessmentLinkedCandidate(assessment)
      : (change?.linkedCandidate && typeof change.linkedCandidate === "object" ? change.linkedCandidate : null);
    const hydratedAssessment = assessment ? hydrateAssessmentCvRefs(assessment, linkedCandidate) : null;
    const deleteMode = type === "DELETE_ROW" || String(change?.mode || change?.visibleMode || "").trim().toLowerCase() === "delete";
    const shouldRefreshStats = Boolean(change?.refreshStats);
    const listMetaDelta = Number(change?.listMetaDelta || 0);
    const statsDelta = change?.statsDelta && typeof change.statsDelta === "object" ? change.statsDelta : null;

    const matchesCurrentVisibleAssessmentView = (row) => {
      if (!row || typeof row !== "object") return false;
      return applyAssessmentFiltersLocal(row, {
        ...(safeAssessmentFiltersApplied && typeof safeAssessmentFiltersApplied === "object" ? safeAssessmentFiltersApplied : {}),
        lane: assessmentLane
      });
    };

    const upsertIntoList = (items = []) => {
      const currentItems = Array.isArray(items) ? items : [];
      if (!hydratedAssessment || !assessmentId) return currentItems;
      if (!matchesCurrentVisibleAssessmentView(hydratedAssessment)) {
        return removeFromList(currentItems);
      }
      const existingIx = currentItems.findIndex((item) => String(item?.id || "").trim() === assessmentId);
      const existingItem = existingIx >= 0 ? currentItems[existingIx] : null;
      const nextRow = hydrateAssessmentCvRefs(
        existingItem && typeof existingItem === "object"
          ? { ...existingItem, ...hydratedAssessment }
          : hydratedAssessment,
        linkedCandidate || resolveAssessmentLinkedCandidate(existingItem) || null
      );
      const nextItems = [...currentItems];
      if (existingIx < 0) {
        nextItems.unshift(nextRow);
        return sortAssessmentsForList(nextItems, assessmentSortBy);
      }
      nextItems.splice(existingIx, 1, { ...nextItems[existingIx], ...nextRow });
      return sortAssessmentsForList(nextItems, assessmentSortBy);
    };

    const removeFromList = (items = []) => (Array.isArray(items) ? items.filter((item) => String(item?.id || "").trim() !== assessmentId) : items);

    if (scope === "backing" || scope === "all") {
      if (type === "RELOAD_SLICE") {
        const nextAssessments = Array.isArray(change?.items) ? change.items : [];
        setState((current) => ({ ...current, assessments: mergeAssessmentsByFreshness(current.assessments, nextAssessments) }));
      } else if (deleteMode) {
        setState((current) => ({
          ...current,
          assessments: removeFromList(current.assessments)
        }));
      } else if (hydratedAssessment) {
        setState((current) => ({
          ...current,
          assessments: mergeAssessmentsByFreshness(current.assessments, [hydratedAssessment])
        }));
      }
    }

    if (scope === "visible" || scope === "all") {
      if (type === "RELOAD_SLICE") {
        const nextItems = Array.isArray(change?.items) ? change.items : [];
        setAssessmentListItems(nextItems);
        if (nextItems.length) {
          setAssessmentOptionPool((current) => mergeAssessmentsByFreshness(current, nextItems));
        }
        if (change?.meta && typeof change.meta === "object") {
          setAssessmentListMeta((current) => ({
            ...(current && typeof current === "object" ? current : {}),
            ...change.meta
          }));
        }
      } else if (deleteMode) {
        setAssessmentListItems((current) => removeFromList(current));
        setAssessmentOptionPool((current) => removeFromList(current));
      } else if (hydratedAssessment) {
        setAssessmentListItems((current) => upsertIntoList(current));
        setAssessmentOptionPool((current) => mergeAssessmentsByFreshness(current, [hydratedAssessment]));
      }
    }

    if (listMetaDelta && scope !== "backing") {
      setAssessmentListMeta((current) => {
        const currentMeta = current && typeof current === "object" ? current : {};
        const previousTotal = Math.max(0, Number(currentMeta.total || 0));
        const nextTotal = Math.max(0, previousTotal + listMetaDelta);
        const limit = Math.max(1, Number(currentMeta.limit || safeAssessmentApiPageSize || 25));
        const nextTotalPages = Math.max(1, Math.ceil(nextTotal / limit));
        const nextPage = Math.min(Math.max(1, Number(currentMeta.page || assessmentPage || 1)), nextTotalPages);
        return {
          ...currentMeta,
          total: nextTotal,
          totalPages: nextTotalPages,
          page: nextPage,
          limit
        };
      });
    }

    if (statsDelta && scope !== "backing") {
      setAssessmentStatsSnapshot((current) => {
        const next = current && typeof current === "object"
          ? { ...current }
          : { today: 0, total: 0, active: 0, archived: 0 };
        Object.entries(statsDelta).forEach(([key, delta]) => {
          const numericDelta = Number(delta || 0);
          if (!Number.isFinite(numericDelta) || !numericDelta) return;
          next[key] = Math.max(0, Number(next[key] || 0) + numericDelta);
        });
        return next;
      });
    }

    if (assessmentStatusId && assessmentId && String(assessmentStatusId || "").trim() === assessmentId) {
      if (deleteMode) {
        setAssessmentStatusItemSnapshot(null);
      } else if (hydratedAssessment) {
        setAssessmentStatusItemSnapshot(hydratedAssessment);
      }
    }

    if (shouldRefreshStats && scope !== "backing") {
      void reloadAssessmentStats(assessmentFiltersApplied).catch(() => {});
    }
  }

  function hydrateAssessmentCvRefs(assessment = {}, linkedCandidate = null) {
    const base = assessment && typeof assessment === "object" ? assessment : {};
    const candidate = linkedCandidate && typeof linkedCandidate === "object" ? linkedCandidate : null;
    const candidateMetaSource = candidate || base?.raw?.candidate || base?.candidate || base;
    const cvMeta = getCandidateProfileCvMeta(candidateMetaSource || {});
    return {
      ...base,
      cv_provider: base.cv_provider || base.cvProvider || cvMeta.provider || "",
      cv_key: base.cv_key || base.cvKey || cvMeta.key || "",
      cv_url: base.cv_url || base.cvUrl || cvMeta.url || "",
      cv_filename: base.cv_filename || base.cvFilename || cvMeta.filename || "",
      cvAnalysis: base.cvAnalysis || base.cv_analysis || candidate?.cvAnalysis || candidate?.cv_analysis || base?.raw?.candidate?.cvAnalysis || base?.raw?.candidate?.cv_analysis || null
    };
  }

  function patchVisibleAssessmentRow(saved, mode = "upsert") {
    applyAssessmentChange({
      type: mode === "delete" ? "DELETE_ROW" : "PATCH_ROW",
      scope: "visible",
      assessment: saved,
      visibleMode: mode,
      source: "LOCAL_PATCH"
    });
  }

  async function refreshCandidateRowById(candidateId) {
    const safeCandidateId = String(candidateId || "").trim();
    if (!token || !safeCandidateId) return null;
    const rows = await api(`/candidates?id=${encodeURIComponent(safeCandidateId)}&scope=company&limit=1`, token).catch(() => []);
    const nextRows = Array.isArray(rows) ? rows : [];
    const nextRow = nextRows.length ? nextRows[0] : null;
    if (!nextRow) return null;
    setState((current) => ({
      ...current,
      candidates: upsertCandidatesById(current.candidates, nextRows),
      databaseCandidates: upsertCandidatesById(current.databaseCandidates, nextRows)
    }));
    return nextRow;
  }

  async function syncPostAssessmentMutation({
    candidateId = "",
    refreshCandidate = true,
    refreshList = false,
    refreshStats = false
  } = {}) {
    const safeCandidateId = String(candidateId || "").trim();
    const tasks = [
    ];
    if (refreshList) {
      tasks.push(reloadAssessmentSlice(assessmentPage, safeAssessmentApiPageSize, assessmentFiltersApplied, assessmentLane, assessmentSortBy));
    }
    if (refreshStats) {
      tasks.push(reloadAssessmentStats(assessmentFiltersApplied));
    }
    if (refreshCandidate && safeCandidateId) {
      tasks.push(refreshCandidateRowById(safeCandidateId));
    }
    return Promise.all(tasks);
  }

  async function refreshAssessmentFallback({ candidateId = "", refreshCandidate = true } = {}) {
    return syncPostAssessmentMutation({
      candidateId,
      refreshCandidate,
      refreshList: true,
      refreshStats: true
    });
  }

  async function applyCandidateLiveRowEvent({ eventType = "", candidateId = "", payloadCandidate = null }) {
    const safeCandidateId = String(candidateId || "").trim();
    if (!safeCandidateId) return;
    const mutationContext = {
      state,
      setState,
      setCapturedOptionPool,
      setCapturedListItems,
      applicantFiltersApplied,
      candidateFiltersApplied,
      applicantSortBy,
      capturedSortBy,
      applicantUser: state.user || null,
      user: state.user || null
    };
    const rows = payloadCandidate && typeof payloadCandidate === "object"
      ? [payloadCandidate]
      : await api(`/candidates?id=${encodeURIComponent(safeCandidateId)}&scope=company&limit=1`, token);
    const nextRows = Array.isArray(rows) ? rows.map((row) => normalizeApplicantVisibleRow({
      ...(state.applicants || []).find((item) => String(item?.id || "") === safeCandidateId) || {},
      ...(row || {}),
      candidateName: String(row?.name || row?.candidateName || row?.candidate_name || "").trim(),
      currentCompany: String(row?.company || row?.currentCompany || row?.current_company || "").trim(),
      currentDesignation: String(row?.role || row?.current_designation || row?.currentDesignation || "").trim(),
      totalExperience: String(row?.experience || row?.totalExperience || row?.total_experience || "").trim(),
      clientName: String(row?.client_name || row?.clientName || "").trim(),
      jdTitle: String(
        row?.jd_title
        || row?.assigned_jd_title
        || row?.role
        || ""
      ).trim(),
      assignedToName: String(
        row?.assignedToName
        || row?.assigned_to_name
        || ""
      ).trim(),
      assigned_to_name: String(
        row?.assigned_to_name
        || row?.assignedToName
        || ""
      ).trim(),
      assignedToUserId: String(
        row?.assignedToUserId
        || row?.assigned_to_user_id
        || ""
      ).trim(),
      assigned_to_user_id: String(
        row?.assigned_to_user_id
        || row?.assignedToUserId
        || ""
      ).trim(),
      assignedAt: String(
        row?.assignedAt
        || row?.assigned_at
        || row?.createdAt
        || row?.created_at
        || ""
      ).trim(),
      assigned_at: String(
        row?.assigned_at
        || row?.assignedAt
        || row?.created_at
        || row?.createdAt
        || ""
      ).trim(),
      createdAt: String(row?.createdAt || row?.created_at || "").trim(),
      created_at: String(row?.created_at || row?.createdAt || "").trim(),
      updatedAt: String(row?.updatedAt || row?.updated_at || "").trim(),
      updated_at: String(row?.updated_at || row?.updatedAt || "").trim(),
      phone: String(row?.phone || row?.phoneNumber || "").trim(),
      email: String(row?.email || row?.emailId || "").trim(),
      location: String(row?.location || "").trim(),
      source: String(row?.source || row?.sourcePlatform || "").trim(),
      sourcePlatform: String(row?.sourcePlatform || row?.source || "").trim()
    })) : [];
    const nextRow = nextRows && nextRows.length ? nextRows[0] : null;
    const previousRow = (state.candidates || []).find((item) => String(item?.id || "") === safeCandidateId) || null;
    if (eventType === "candidate_deleted" || !nextRow) {
      setState((current) => ({
        ...current,
        candidates: (current.candidates || []).filter((item) => String(item?.id || "") !== safeCandidateId),
        databaseCandidates: (current.databaseCandidates || []).filter((item) => String(item?.id || "") !== safeCandidateId),
        applicants: (current.applicants || []).filter((item) => String(item?.id || "") !== safeCandidateId),
        applicantListItems: (current.applicantListItems || []).filter((item) => String(item?.id || "") !== safeCandidateId)
      }));
      setCapturedOptionPool((current) => removeCandidatesById(current, [safeCandidateId]));
      setCapturedListItems((current) => removeCandidatesById(current, [safeCandidateId]));
      return;
    }
    const resolved = resolveCandidateBucket(nextRow, eventType, {
      previousRow,
      source: String(nextRow?.source || nextRow?.sourcePlatform || "").trim()
    });
    applyCandidateChange(nextRow, resolved, `SSE:${eventType}`, mutationContext);
    const previousHidden = Boolean(previousRow?.hidden_from_captured);
    const nextHidden = Boolean(nextRow?.hidden_from_captured);
    const previousUsed = Boolean(previousRow?.used_in_assessment);
    const nextUsed = Boolean(nextRow?.used_in_assessment);
    const previousAssessmentId = String(previousRow?.assessment_id || previousRow?.assessmentId || "").trim();
    const nextAssessmentId = String(nextRow?.assessment_id || nextRow?.assessmentId || "").trim();
    const membershipChanged = previousHidden !== nextHidden || previousUsed !== nextUsed || previousAssessmentId !== nextAssessmentId;
    if (membershipChanged) {
      if (resolved.bucket === "applicants") {
        void reloadApplicantStats(mutationContext.applicantFiltersApplied).catch(() => {});
      } else {
        void reloadCapturedStats(mutationContext.candidateFiltersApplied).catch(() => {});
      }
    }
  }

  async function setAssessmentArchivedState(assessment, archived, options = {}) {
    const safeAssessment = assessment && typeof assessment === "object" ? assessment : null;
    if (!safeAssessment?.id) {
      setStatus("assessments", "Assessment id missing.", "error");
      return null;
    }
    const candidateId = String(safeAssessment?.candidateId || "").trim();
    if (!candidateId) {
      setStatus("assessments", "Candidate id missing for this assessment (cannot archive/restore safely).", "error");
      return null;
    }
    const lockKey = String(safeAssessment?.id || safeAssessment?.candidateId || "").trim();
    if (lockKey && assessmentStatusSaveLockRef.current.has(lockKey)) {
      setStatus("assessments", "Assessment action already in progress for this candidate. Please wait.", "error");
      return null;
    }
    if (lockKey) {
      assessmentStatusSaveLockRef.current.add(lockKey);
      setAssessmentActionBusyIds((current) => ({ ...current, [lockKey]: true }));
    }
    const nowIso = new Date().toISOString();
    const wasArchived = Boolean(isAssessmentArchived(safeAssessment));
    const laneMatchesNewState = Boolean(archived) === (assessmentLane === "archived");
    const listDelta = laneMatchesNewState ? 1 : -1;
    const next = {
      ...safeAssessment,
      candidateId,
      archived: Boolean(archived),
      archivedAt: archived ? nowIso : "",
      archivedBy: archived ? String(state.user?.name || "").trim() : ""
    };
    const optimisticAssessment = {
      ...safeAssessment,
      ...next,
      payload: {
        ...((safeAssessment && safeAssessment.payload && typeof safeAssessment.payload === "object") ? safeAssessment.payload : {}),
        archived: Boolean(archived),
        archived_at: archived ? nowIso : "",
        archived_by: archived ? String(state.user?.name || "").trim() : ""
      }
    };
    setStatus("assessments", archived ? "Archiving assessment..." : "Restoring assessment...");
    applyAssessmentChange({
      type: "ARCHIVE_ROW",
      scope: "all",
      assessment: optimisticAssessment,
      visibleMode: laneMatchesNewState ? "upsert" : "delete",
      listMetaDelta: listDelta,
      statsDelta: {
        active: Boolean(archived) ? -1 : 1,
        archived: Boolean(archived) ? 1 : -1
      },
      source: "LOCAL_PATCH"
    });
    try {
      const saved = await api("/company/assessments", token, "POST", { assessment: next });
      applyAssessmentChange({
        type: "ARCHIVE_ROW",
        scope: "all",
        assessment: saved,
        visibleMode: laneMatchesNewState ? "upsert" : "delete",
        source: "MUTATION_SUCCESS"
      });
      setStatus("assessments", archived ? "Assessment archived." : "Assessment restored.", "ok");
      void syncPostAssessmentMutation({ candidateId }).catch(() => {});
      void refreshDashboardAfterAssessmentChange().catch(() => {});
      void reloadAssessmentSlice(assessmentPage, safeAssessmentApiPageSize, safeAssessmentFiltersApplied, assessmentLane, assessmentSortBy).catch(() => {});
      void reloadAssessmentStats(safeAssessmentFiltersApplied).catch(() => {});
      return saved;
    } catch (error) {
      const message = String(error?.message || error);
      // Edge case: the candidate row was deleted, so Supabase restore fails the visibility check.
      // Recover by asking backend to recreate the missing candidate and restore the assessment.
      if (!archived && /candidate not found or not allowed/i.test(message)) {
        try {
          const restored = await api("/company/assessments/restore", token, "POST", { assessmentId: safeAssessment.id });
          applyAssessmentChange({
            type: "ARCHIVE_ROW",
            scope: "all",
            assessment: restored,
            visibleMode: Boolean(isAssessmentArchived(restored)) === (assessmentLane === "archived") ? "upsert" : "delete",
            source: "MUTATION_SUCCESS"
          });
          setStatus("assessments", "Assessment restored.", "ok");
          void refreshAssessmentFallback({ candidateId }).catch(() => {});
          void refreshDashboardAfterAssessmentChange().catch(() => {});
          return restored;
        } catch (restoreError) {
          setStatus("assessments", String(restoreError?.message || restoreError), "error");
          return null;
        }
      }
      applyAssessmentChange({
        type: "ARCHIVE_ROW",
        scope: "all",
        assessment: safeAssessment,
        visibleMode: wasArchived === (assessmentLane === "archived") ? "upsert" : "delete",
        listMetaDelta: -listDelta,
        statsDelta: {
          active: Boolean(archived) ? 1 : -1,
          archived: Boolean(archived) ? -1 : 1
        },
        source: "LOCAL_PATCH"
      });
      void reloadAssessmentSlice(assessmentPage, safeAssessmentApiPageSize, safeAssessmentFiltersApplied, assessmentLane, assessmentSortBy).catch(() => {});
      void reloadAssessmentStats(safeAssessmentFiltersApplied).catch(() => {});
      setStatus("assessments", message, "error");
      return null;
    } finally {
      if (lockKey) {
        assessmentStatusSaveLockRef.current.delete(lockKey);
        setAssessmentActionBusyIds((current) => {
          const next = { ...current };
          delete next[lockKey];
          return next;
        });
      }
    }
  }

  async function moveAssessmentBackToCaptured(assessment) {
    const safeAssessment = assessment && typeof assessment === "object" ? assessment : null;
    const assessmentId = String(safeAssessment?.id || "").trim();
    const candidateId = String(safeAssessment?.candidateId || "").trim();
    if (!assessmentId) {
      setStatus("assessments", "Assessment id missing.", "error");
      return;
    }
    if (!candidateId) {
      setStatus("assessments", "Candidate id missing for this assessment (cannot move back safely).", "error");
      return;
    }
    const existingCandidate = (state.candidates || []).find((item) => String(item?.id || "") === candidateId)
      || (state.databaseCandidates || []).find((item) => String(item?.id || "") === candidateId)
      || null;
    const linkedCandidate = resolveAssessmentLinkedCandidate(safeAssessment) || existingCandidate;
    const restoreToApplicants = isInboundApplicantSource(
      linkedCandidate?.source
      || safeAssessment?.source
      || safeAssessment?.sourcePlatform
      || safeAssessment?.payload?.source
      || safeAssessment?.payload?.sourcePlatform
      || ""
    );
    const destinationLabel = restoreToApplicants ? "Applied Candidates" : "Captured";
    const confirmed = typeof window === "undefined" || window.confirm(
      `Move back to ${destinationLabel} will remove this assessment and keep the candidate in ${destinationLabel}. Continue?`
    );
    if (!confirmed) return;
    const lockKey = String(safeAssessment?.id || safeAssessment?.candidateId || "").trim();
    if (lockKey && assessmentStatusSaveLockRef.current.has(lockKey)) {
      setStatus("assessments", "Assessment action already in progress for this candidate. Please wait.", "error");
      return;
    }
    if (lockKey) {
      assessmentStatusSaveLockRef.current.add(lockKey);
      setAssessmentActionBusyIds((current) => ({ ...current, [lockKey]: true }));
    }
    setStatus("assessments", `Moving back to ${destinationLabel}...`);
    const optimisticUpdatedAt = new Date().toISOString();
    const currentCapturedActiveStates = Array.isArray(candidateFiltersApplied.activeStates) && candidateFiltersApplied.activeStates.length
      ? candidateFiltersApplied.activeStates
      : ["Active"];
    const currentApplicantActiveStates = Array.isArray(applicantFiltersApplied.activeStates) && applicantFiltersApplied.activeStates.length
      ? applicantFiltersApplied.activeStates
      : ["Active"];
    const shouldRemainVisible = restoreToApplicants
      ? currentApplicantActiveStates.includes("Active")
      : currentCapturedActiveStates.includes("Active");
    const restoredCandidatePreview = {
      ...(existingCandidate || {}),
      id: candidateId,
      assessment_id: "",
      assessmentId: "",
      used_in_assessment: false,
      assessment_status: "",
      hidden_from_captured: false,
      updated_at: optimisticUpdatedAt,
      updatedAt: optimisticUpdatedAt
    };
    const restoredApplicantPreview = normalizeApplicantVisibleRow({
      ...(linkedCandidate || {}),
      ...(safeAssessment || {}),
      ...(restoredCandidatePreview || {}),
      candidateName: String(safeAssessment?.candidateName || linkedCandidate?.name || "").trim(),
      currentCompany: String(safeAssessment?.currentCompany || linkedCandidate?.company || "").trim(),
      currentDesignation: String(safeAssessment?.currentDesignation || safeAssessment?.jdTitle || linkedCandidate?.role || "").trim(),
      totalExperience: String(safeAssessment?.totalExperience || linkedCandidate?.experience || "").trim(),
      clientName: String(safeAssessment?.clientName || linkedCandidate?.client_name || "").trim(),
      jdTitle: String(safeAssessment?.jdTitle || linkedCandidate?.jd_title || "").trim(),
      sourcePlatform: String(linkedCandidate?.source || safeAssessment?.source || safeAssessment?.sourcePlatform || "").trim(),
      source: String(linkedCandidate?.source || safeAssessment?.source || safeAssessment?.sourcePlatform || "").trim()
    });
    const patchCandidateState = (items) => Array.isArray(items)
      ? items.map((item) => String(item?.id || "") === candidateId ? { ...item, ...restoredCandidatePreview } : item)
      : items;
    const prevApplicantListItems = Array.isArray(state.applicantListItems) ? [...state.applicantListItems] : state.applicantListItems;
    const prevApplicantListMeta = applicantListMeta && typeof applicantListMeta === "object" ? { ...applicantListMeta } : applicantListMeta;
    const prevApplicantStats = applicantStatsSnapshot && typeof applicantStatsSnapshot === "object" ? { ...applicantStatsSnapshot } : applicantStatsSnapshot;
    applyAssessmentChange({
      type: "MOVE_BACK_TO_CAPTURED",
      scope: "all",
      assessmentId,
      assessment: safeAssessment,
      visibleMode: "delete",
      listMetaDelta: -1,
      statsDelta: {
        active: -1,
        total: -1
      },
      source: "LOCAL_PATCH"
    });
    setState((current) => ({
      ...current,
      candidates: patchCandidateState(current.candidates),
      databaseCandidates: patchCandidateState(current.databaseCandidates),
      applicants: restoreToApplicants
        ? sortApplicantsForList(upsertCandidatesById(current.applicants, [restoredApplicantPreview]), applicantSortBy)
        : current.applicants,
      applicantListItems: restoreToApplicants
        ? (shouldRemainVisible
          ? sortApplicantsForList(upsertCandidatesById(current.applicantListItems, [restoredApplicantPreview]), applicantSortBy)
          : removeCandidatesById(current.applicantListItems, [candidateId]))
        : current.applicantListItems
    }));
    if (restoreToApplicants) {
      if (shouldRemainVisible) {
        setApplicantListMeta((current) => {
          const meta = current && typeof current === "object" ? current : {};
          const nextTotal = Math.max(0, Number(meta.total || 0) + 1);
          const limit = Math.max(1, Number(meta.limit || safeApplicantApiPageSize || 25));
          const nextTotalPages = Math.max(1, Math.ceil(nextTotal / limit));
          return {
            ...meta,
            total: nextTotal,
            totalPages: nextTotalPages,
            page: Math.min(Math.max(1, Number(meta.page || applicantPage || 1)), nextTotalPages),
            limit
          };
        });
      }
      setApplicantStatsSnapshot((current) => {
        if (!current || typeof current !== "object") return current;
        return {
          ...current,
          active: Math.max(0, Number(current.active || 0) + 1),
          converted: Math.max(0, Number(current.converted || 0) - 1)
        };
      });
    } else {
      setCapturedListItems((current) => (shouldRemainVisible
        ? upsertCandidatesById(current, [restoredCandidatePreview])
        : (Array.isArray(current) ? current.filter((item) => String(item?.id || "") !== candidateId) : current)));
      setCapturedOptionPool((current) => upsertCandidatesById(current, [restoredCandidatePreview]));
      if (shouldRemainVisible) {
        setCapturedListMeta((current) => {
          const meta = current && typeof current === "object" ? current : {};
          const nextTotal = Math.max(0, Number(meta.total || 0) + 1);
          const limit = Math.max(1, Number(meta.limit || safeCapturedApiPageSize || 25));
          const nextTotalPages = Math.max(1, Math.ceil(nextTotal / limit));
          return {
            ...meta,
            total: nextTotal,
            totalPages: nextTotalPages,
            page: Math.min(Math.max(1, Number(meta.page || capturedPage || 1)), nextTotalPages),
            limit
          };
        });
      }
      setCapturedStatsSnapshot((current) => {
        if (!current || typeof current !== "object") return current;
        return {
          ...current,
          active: Math.max(0, Number(current.active || 0) + 1),
          converted: Math.max(0, Number(current.converted || 0) - 1)
        };
      });
    }
    if (restoreToApplicants) {
      setCapturedListItems((current) => removeCandidatesById(current, [candidateId]));
      setCapturedOptionPool((current) => removeCandidatesById(current, [candidateId]));
    }
    try {
      await api("/company/assessments", token, "DELETE", { assessmentId });
      // Clear the candidate link so it shows up in captured notes again.
      await patchCandidateQuiet(candidateId, {
        assessment_id: "",
        used_in_assessment: false,
        assessment_status: "",
        hidden_from_captured: false
      }, { skipRefresh: true });
      navigate(restoreToApplicants ? "/applicants" : "/captured-notes");
      void refreshDashboardAfterAssessmentChange().catch(() => {});
      setStatus(restoreToApplicants ? "applicants" : "captured", `Moved back to ${destinationLabel}.`, "ok");
    } catch (error) {
      if (restoreToApplicants) {
        setApplicantListMeta(prevApplicantListMeta);
        setApplicantStatsSnapshot(prevApplicantStats);
      } else {
        setCapturedListItems(prevCapturedListItems);
        setCapturedOptionPool(prevCapturedOptionPool);
        setCapturedListMeta(prevCapturedListMeta);
        setCapturedStatsSnapshot(prevCapturedStats);
      }
      void reloadAssessmentSlice(assessmentPage, safeAssessmentApiPageSize, assessmentFiltersApplied, assessmentLane, assessmentSortBy).catch(() => {});
      void reloadAssessmentStats(assessmentFiltersApplied).catch(() => {});
      setState((current) => ({
        ...current,
        applicants: prevApplicantListItems,
        applicantListItems: prevApplicantListItems,
        candidates: patchCandidateState(current.candidates),
        databaseCandidates: patchCandidateState(current.databaseCandidates)
      }));
      setStatus("assessments", String(error?.message || error), "error");
    } finally {
      if (lockKey) {
        assessmentStatusSaveLockRef.current.delete(lockKey);
        setAssessmentActionBusyIds((current) => {
          const next = { ...current };
          delete next[lockKey];
          return next;
        });
      }
    }
  }

