  function isGarbageCvFieldValue(value = "") {
    const text = String(value || "").trim().toLowerCase();
    if (!text) return true;
    if (/(employment\s+profile|to\s+work\s+with|career\s+objective)/i.test(text)) return true;
    const words = text.split(/\s+/).filter(Boolean);
    if (words.length > 10 && !/\b(b[\s.-]*tech|b[\s.-]*e\.?|mba|m[\s.-]*tech|mca|bca|b[\s.-]*sc|m[\s.-]*sc|b[\s.-]*com|m[\s.-]*com|ph\.?\s*d|diploma)\b/i.test(text)) {
      return true;
    }
    return false;
  }

  function pickQualificationFromEducation(educationRows = [], fallbackText = "") {
    const rows = Array.isArray(educationRows) ? educationRows : [];
    const rankDegree = (degree = "") => {
      const d = String(degree || "").toLowerCase();
      if (/\b(ph\.?\s*d|doctorate)\b/.test(d)) return 6;
      if (/\b(post\s*graduation|post\s*graduate|pg|mba|pgdm|m[\s.-]*tech|mca|masters?|m[\s.-]*e\.?|m[\s.-]*sc|m[\s.-]*com|m[\s.-]*a)\b/.test(d)) return 5;
      if (/\b(b[\s.-]*tech|b[\s.-]*e\.?|bca|bachelor|b[\s.-]*sc|b[\s.-]*com|b[\s.-]*a)\b/.test(d)) return 4;
      if (/\b(diploma)\b/.test(d)) return 3;
      if (/\b(12th|xii|hsc)\b/.test(d)) return 2;
      if (/\b(10th|ssc|matric)\b/.test(d)) return 1;
      return 0;
    };
    const ranked = rows
      .map((row) => {
        const degree = String(row?.degree || "").trim();
        return { text: degree, score: rankDegree(degree), year: String(row?.end_date || row?.year || row?.start_date || "").trim() };
      })
      .filter((item) => item.text && item.score > 0 && !isGarbageCvFieldValue(item.text))
      .sort((a, b) => {
        if (b.score !== a.score) return b.score - a.score;
        return Number(b.year || 0) - Number(a.year || 0);
      });
    if (ranked.length) return ranked[0].text;
    const fallback = String(fallbackText || "").trim();
    if (!fallback || isGarbageCvFieldValue(fallback)) return "";
    if (!/\b(b[\s.-]*tech|b[\s.-]*e\.?|mba|m[\s.-]*tech|mca|bca|bachelor|masters?|b[\s.-]*sc|m[\s.-]*sc|b[\s.-]*com|m[\s.-]*com|ph\.?\s*d|diploma)\b/i.test(fallback)) {
      return "";
    }
    return fallback;
  }

  async function importNewDraftFromCv(file) {
    if (!file) return;
    try {
      setNewDraftImportBusy(true);
      setNewDraftBusyMessage("Parsing CV...");
      setStatus("captured", "Parsing CV for draft...");
      setNewDraftCvParsePreview(null);
      resetNewDraftForm();
      setNewDraftMode("cv");
      setNewDraftOpen(true);
      const fileData = await fileToBase64(file);
      const parsed = await api("/parse-candidate", token, "POST", {
        sourceType: "cv",
        normalizeWithAi: true,
        file: {
          filename: file.name || "candidate-cv.pdf",
          mimeType: file.type || "application/octet-stream",
          fileData
        }
      });
      let parsedResult = parsed?.result && typeof parsed.result === "object" ? parsed.result : parsed;
      const fixedSchema = parsedResult?.fixed_schema && typeof parsedResult.fixed_schema === "object"
        ? parsedResult.fixed_schema
        : parsedResult;
      const fixedSummary = fixedSchema?.summary && typeof fixedSchema.summary === "object"
        ? fixedSchema.summary
        : {};
      const normalizedExperience = Array.isArray(parsedResult?.experience_history) && parsedResult.experience_history.length
        ? parsedResult.experience_history
        : (Array.isArray(parsedResult?.experienceTimeline)
          ? parsedResult.experienceTimeline.map((item) => ({
              designation: String(item?.designation || "").trim(),
              company_name: String(item?.company || "").trim(),
              start_date: String(item?.startDate || "").trim(),
              end_date: String(item?.endDate || "").trim(),
              duration: "",
              raw_line: String(item?.sourceText || "").trim()
            }))
          : []);
      const normalizedEducation = Array.isArray(parsedResult?.education_history) && parsedResult.education_history.length
        ? parsedResult.education_history
        : (Array.isArray(parsedResult?.education)
          ? parsedResult.education.map((item) => ({
              degree: String(item?.degree || "").trim(),
              institution: String(item?.institution || "").trim(),
              start_date: String(item?.startDate || "").trim(),
              end_date: String(item?.endDate || "").trim(),
              year: String(item?.year || "").trim(),
              grade: String(item?.score || "").trim(),
              raw_line: String(item?.rawText || "").trim()
            }))
          : []);
      const strictSummary = getDeterministicSummaryFromResult(parsedResult)
        || deriveStrictCvSummaryFromRows(normalizedExperience, normalizedEducation);
      const latestExperience = normalizedExperience[0] || null;
      let resolvedCompany = String(strictSummary.currentCompany || "").trim();
      let resolvedDesignation = String(strictSummary.currentDesignation || "").trim();
      if (!resolvedCompany || isGarbageCvFieldValue(resolvedCompany)) {
        resolvedCompany = String(latestExperience?.company_name || "").trim() || resolvedCompany;
      }
      if (!resolvedDesignation || /^company\b/i.test(resolvedDesignation) || isGarbageCvFieldValue(resolvedDesignation)) {
        resolvedDesignation = String(latestExperience?.designation || "").trim() || resolvedDesignation;
      }
      if (isGarbageCvFieldValue(resolvedCompany)) resolvedCompany = "";
      if (isGarbageCvFieldValue(resolvedDesignation)) resolvedDesignation = "";
      const resolvedTotalExperience = String(strictSummary.totalExperience || "").trim();
      const resolvedCurrentOrgTenure = String(strictSummary.currentOrgTenure || "").trim();
      const resolvedQualification = String(strictSummary.highestEducation || "").trim();
      const resolvedPhone = String(
        fixedSummary?.phoneNumber ||
        fixedSummary?.phone ||
        parsedResult?.phoneNumber ||
        parsedResult?.phone ||
        strictSummary?.phoneNumber ||
        strictSummary?.phone ||
        ""
      ).trim();
      const resolvedEmail = String(
        fixedSummary?.emailId ||
        fixedSummary?.email ||
        parsedResult?.emailId ||
        parsedResult?.email ||
        strictSummary?.emailId ||
        strictSummary?.email ||
        ""
      ).trim();
      const resolvedLinkedin = String(
        fixedSummary?.linkedinUrl ||
        fixedSummary?.linkedin ||
        parsedResult?.linkedinUrl ||
        parsedResult?.linkedin ||
        strictSummary?.linkedinUrl ||
        strictSummary?.linkedin ||
        ""
      ).trim();
      let resolvedLocation = String(fixedSummary?.location || parsedResult?.location || "").trim();
      const lcResolvedCompany = String(resolvedCompany || "").trim().toLowerCase();
      const lcResolvedDesignation = String(resolvedDesignation || "").trim().toLowerCase();
      const lcResolvedLocation = resolvedLocation.toLowerCase();
      if (
        !resolvedLocation ||
        isLikelyRoleLikeLocation(resolvedLocation) ||
        lcResolvedLocation === lcResolvedCompany ||
        lcResolvedLocation === lcResolvedDesignation
      ) {
        resolvedLocation = "";
      }
      setNewDraftCvParsePreview({
        summary: {
          candidateName: String(fixedSummary?.candidate_name || parsedResult?.candidateName || "").trim(),
          phoneNumber: resolvedPhone,
          emailId: resolvedEmail,
          linkedinUrl: resolvedLinkedin,
          location: resolvedLocation,
          currentCompany: resolvedCompany,
          currentDesignation: resolvedDesignation,
          totalExperience: resolvedTotalExperience,
          highestEducation: resolvedQualification,
          currentOrgTenure: resolvedCurrentOrgTenure
        },
        experience: normalizedExperience,
        education: normalizedEducation,
        warnings: Array.isArray(parsedResult?.parser_warnings) ? parsedResult.parser_warnings : (Array.isArray(parsedResult?.parserWarnings) ? parsedResult.parserWarnings : []),
        confidence: parsedResult?.parser_confidence || parsedResult?.confidence || null
      });
      setNewDraftCvParsedPatch({
        name: String(parsedResult?.candidateName || file.name?.replace(/\.[^.]+$/, "") || "").trim(),
        phone: resolvedPhone,
        email: resolvedEmail,
        linkedin: resolvedLinkedin,
        company: resolvedCompany || String(parsedResult?.currentCompany || "").trim(),
        current_designation: resolvedDesignation || String(parsedResult?.currentDesignation || "").trim(),
        total_experience: resolvedTotalExperience,
        current_org_tenure: resolvedCurrentOrgTenure,
        location: resolvedLocation,
        current_ctc: String(parsedResult?.currentCtc || "").trim(),
        notice_period: String(parsedResult?.noticePeriod || "").trim(),
        highest_education: resolvedQualification
      });
      setStatus("captured", "CV parsed. Review preview and click Apply parsed values to draft.", "ok");
    } catch (error) {
      setStatus("captured", String(error?.message || error), "error");
    } finally {
      setNewDraftImportBusy(false);
      setNewDraftBusyMessage("");
    }
  }

