                            <label><span>Client name</span><input value={getClientUserEditDraft(item).clientName} onChange={(e) => setClientUserEditDrafts((current) => ({ ...current, [item.id]: { ...getClientUserEditDraft(item), clientName: e.target.value } }))} /></label>
