const SHEET_IGNORED_HEADER_TOKENS = new Set([
  "s no",
  "s no ",
  "sno",
  "sr no",
  "serial no",
  "serial number"
]);

function buildSheetHeaderSignature(headers = []) {
  const tokens = (Array.isArray(headers) ? headers : [])
    .map((header) => normalizeSheetHeaderToken(header))
    .filter(Boolean);
  return tokens.join("|").slice(0, 600);
}

function detectInitialSheetColumnMapping(headers = [], learnedAliases = {}) {
  const mapping = {};
  const normalizedHeaders = (Array.isArray(headers) ? headers : []).map((header) => normalizeSheetHeaderToken(header));
  normalizedHeaders.forEach((token) => {
    if (!token) return;
    for (const option of SHEET_IMPORT_FIELD_OPTIONS) {
      const field = option.key;
      const aliases = [
        ...(SHEET_FIELD_ALIASES[field] || []),
        ...((Array.isArray(learnedAliases?.[field]) ? learnedAliases[field] : []))
      ];
      const hasMatch = aliases.some((alias) => {
        const needle = normalizeSheetHeaderToken(alias);
        return needle && (token === needle || token.includes(needle));
      });
      if (hasMatch) {
        mapping[token] = field;
        break;
      }
    }
  });
  return mapping;
}

function mapDraftAutofillFromSpreadsheetRows(rows = []) {
  if (!Array.isArray(rows) || rows.length < 2) return null;
  const headers = rows[0].map((item) => String(item || ""));
  const values = rows[1] || [];
  const getValue = (...aliases) => getSheetValueByAliases(headers, values, aliases);
  return {
    name: getValue("name", "candidate name", "full name"),
    phone: getValue("phone", "mobile", "contact", "phone number"),
    email: getValue("email", "email id", "mail"),
    linkedin: getValue("linkedin", "linkedin url", "linkedin profile"),
    company: getValue("company", "current company", "organization"),
    current_designation: getValue("designation", "current designation", "current role", "current position"),
    total_experience: getValue("experience", "total experience", "work experience"),
    location: getValue("location", "city"),
    jd_title: getValue("jd", "role", "position", "job title"),
    client_name: getValue("client", "client name"),
    tags: getValue("skill", "skills", "keywords", "tags"),
    notes: getValue("note", "notes", "remarks"),
    current_ctc: getValue("current ctc", "ctc"),
    notice_period: getValue("notice", "notice period"),
    highest_education: getValue("qualification", "education", "highest education")
  };
}

function normalizeSheetIdentityValue(value = "") {
  return String(value || "").trim().toLowerCase();
}

function normalizeSheetPhone(value = "") {
  return String(value || "").replace(/[^\d+]/g, "").trim();
}

function isUuidLike(value = "") {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || "").trim());
}

function normalizeImportedContactAttemptOutcome(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  const normalized = normalizeAttemptOutcomeLabel(raw);
  if (ATTEMPT_OUTCOME_OPTIONS.includes(normalized)) return normalized;
  const key = raw.toLowerCase().replace(/[_-]+/g, " ").replace(/\s+/g, " ").trim();
  const map = {
    "cv shared": "JD shared",
    "jd sent": "JD shared",
    "shared": "JD shared",
    "joined elsewhere": "Not interested",
    "not looking": "Not interested",
    "already joined": "Not interested",
    "interview reject": "Screening reject",
    "screening reject": "Screening reject",
    "sr": "Screening reject",
    "duplicate profile": "Duplicate",
    "duplicate candidate": "Duplicate",
    "switch off": "Switch Off",
    "switched off": "Switch Off",
    "no response": "Not responding",
    "nr": "Not responding",
    "not received": "Not responding",
    "no reply": "Not responding",
    "not replied": "Not responding",
    "unanswered": "Not responding",
    "call back": "Call later",
    "callback": "Call later",
    "hold": "Hold by recruiter"
  };
  const mapped = map[key] || "";
  if (mapped && ATTEMPT_OUTCOME_OPTIONS.includes(mapped)) return mapped;
  if (/\bnot\s*interested|joined\s*elsewhere|already\s*joined|not\s*looking\b/.test(key)) return "Not interested";
  if (/\bno\s*response|not\s*received|no\s*reply|not\s*replied|unanswered|nr\b/.test(key)) return "Not responding";
  if (/\bswitch\s*off|switched\s*off\b/.test(key)) return "Switch Off";
  if (/\bdisconnected\b/.test(key)) return "Disconnected";
  if (/\bnot\s*reachable\b/.test(key)) return "Not reachable";
  if (/\bcall\s*back|callback|call\s*later|follow\s*up\b/.test(key)) return "Call later";
  if (/\bduplicate\b/.test(key)) return "Duplicate";
  if (/\bjd\s*shared|cv\s*shared|jd\s*sent|shared\b/.test(key)) return "JD shared";
  if (/\binterested\b/.test(key)) return "Interested";
  if (/\bhold\b/.test(key)) return "Hold by recruiter";
  if (/\bscreening\s*reject|interview\s*reject|\bsr\b/.test(key)) return "Screening reject";
  if (/\brevisit\b/.test(key)) return "Revisit for other role";
  if (/\bbusy\b/.test(key)) return "Busy";
  return "No outcome";
}

function buildSheetDraftRows(rows = [], options = {}) {
  if (!Array.isArray(rows) || rows.length < 2) return [];
  const headers = rows[0].map((item) => String(item || ""));
  const normalizedHeaders = headers.map((header) => normalizeSheetHeaderToken(header));
  const manualMapping = options?.mappingByHeaderToken && typeof options.mappingByHeaderToken === "object"
    ? options.mappingByHeaderToken
    : {};
  const learnedAliases = options?.learnedAliases && typeof options.learnedAliases === "object"
    ? options.learnedAliases
    : {};
  const getValueAndMatchedIndex = (values = [], aliases = []) => {
    const aliasList = Array.isArray(aliases) ? aliases : [];
    for (const alias of aliasList) {
      const needle = normalizeSheetHeaderToken(alias);
      if (!needle) continue;
      const idx = normalizedHeaders.findIndex((header) => header === needle || header.includes(needle));
      if (idx >= 0) {
        const value = String(values[idx] || "").trim();
        if (value) return { value, idx };
      }
    }
    return { value: "", idx: -1 };
  };
  return rows.slice(1).map((values, idx) => {
      const matchedIndexSet = new Set();
      const manualFieldValues = {};
      normalizedHeaders.forEach((headerToken, headerIdx) => {
        const mappedField = String(manualMapping?.[headerToken] || "").trim();
        if (!mappedField) return;
        const value = String(values[headerIdx] || "").trim();
        if (!value) return;
        matchedIndexSet.add(headerIdx);
        if (!manualFieldValues[mappedField]) manualFieldValues[mappedField] = value;
      });
      const pick = (fieldKey) => {
        if (manualFieldValues[fieldKey]) return manualFieldValues[fieldKey];
        const hit = getValueAndMatchedIndex(values, SHEET_FIELD_ALIASES[fieldKey] || []);
        if (!hit.value && Array.isArray(learnedAliases?.[fieldKey]) && learnedAliases[fieldKey].length) {
          const learnedHit = getValueAndMatchedIndex(values, learnedAliases[fieldKey] || []);
          if (learnedHit.idx >= 0) matchedIndexSet.add(learnedHit.idx);
          return learnedHit.value;
        }
        if (hit.idx >= 0) matchedIndexSet.add(hit.idx);
        return hit.value;
      };
      const row = {
        id: `sheet-row-${idx + 1}`,
        index: idx + 1,
        name: pick("name"),
        phone: pick("phone"),
        email: pick("email"),
        linkedin: pick("linkedin"),
        company_name: pick("company_name"),
        company: pick("company"),
        current_designation: pick("current_designation"),
        total_experience: pick("total_experience"),
        location: pick("location"),
        jd_title: pick("jd_title") || pick("role"),
        client_name: pick("client_name"),
        tags: pick("tags"),
        notes: pick("notes"),
        current_ctc: pick("current_ctc"),
        expected_ctc: pick("expected_ctc"),
        notice_period: pick("notice_period"),
        highest_education: pick("highest_education"),
        recruiter_name: pick("recruiter_name"),
        recruiter_email: pick("recruiter_email"),
        contact_attempts: ""
      };
      const contactAttemptRaw = String(pick("contact_attempts") || "").trim();
      row.contact_attempts = normalizeImportedContactAttemptOutcome(contactAttemptRaw);
      const contactAttemptNormalizedLabel = normalizeAttemptOutcomeLabel(contactAttemptRaw);
      if (contactAttemptRaw && !ATTEMPT_OUTCOME_OPTIONS.includes(contactAttemptNormalizedLabel)) {
        row.raw_contact_attempts = contactAttemptRaw;
      }
      const extra = {};
      headers.forEach((header, headerIdx) => {
        if (matchedIndexSet.has(headerIdx)) return;
        const token = normalizeSheetHeaderToken(header);
        if (SHEET_IGNORED_HEADER_TOKENS.has(token)) return;
        const key = String(header || "").trim();
        const value = String(values[headerIdx] || "").trim();
        if (!key || !value) return;
        extra[key] = value;
      });
      row.raw_extra_fields = extra;
      if (row.raw_contact_attempts) {
        row.raw_extra_fields.contact_attempts_raw = row.raw_contact_attempts;
      }
      delete row.raw_contact_attempts;
      return row;
    }).filter((row) => Object.keys(row).some((key) => !["id", "index", "raw_extra_fields"].includes(key) && String(row[key] || "").trim()));
}

function resolveSheetAssignedRecruiter(row = {}, users = [], fallback = null) {
  const list = Array.isArray(users) ? users : [];
  const byEmail = String(row?.recruiter_email || "").trim().toLowerCase();
  const byName = String(row?.recruiter_name || "").trim().toLowerCase();
  if (byEmail) {
    const hit = list.find((user) => String(user?.email || "").trim().toLowerCase() === byEmail);
    if (hit) return hit;
  }
  if (byName) {
    const hit = list.find((user) => String(user?.name || "").trim().toLowerCase() === byName);
    if (hit) return hit;
  }
  return fallback || null;
}

function validateSheetDraftRows(rows = [], existingRows = []) {
  const existingIdentitySet = new Set();
  (existingRows || []).forEach((item) => {
    const phone = normalizeSheetPhone(item?.phone || item?.phoneNumber || "");
    const email = normalizeSheetIdentityValue(item?.email || item?.emailId || "");
    const linkedin = normalizeSheetIdentityValue(item?.linkedin || item?.linkedinUrl || "");
    if (phone) existingIdentitySet.add(`phone:${phone}`);
    if (email) existingIdentitySet.add(`email:${email}`);
    if (linkedin) existingIdentitySet.add(`linkedin:${linkedin}`);
  });
  const seenInFile = new Set();
  return (rows || []).map((row) => {
    const issues = [];
    const name = String(row?.name || "").trim();
    const phone = normalizeSheetPhone(row?.phone || "");
    const email = normalizeSheetIdentityValue(row?.email || "");
    const linkedin = normalizeSheetIdentityValue(row?.linkedin || "");
    if (!name) issues.push("Missing name");
    if (!(phone || email)) issues.push("Need at least one contact: phone/email");
    const identities = [];
    if (phone) identities.push(`phone:${phone}`);
    if (email) identities.push(`email:${email}`);
    if (linkedin) identities.push(`linkedin:${linkedin}`);
    const isDuplicateExisting = identities.some((id) => existingIdentitySet.has(id));
    const isDuplicateInFile = identities.some((id) => seenInFile.has(id));
    identities.forEach((id) => seenInFile.add(id));
    if (isDuplicateExisting || isDuplicateInFile) issues.push("Duplicate by phone/email/linkedin");
    const hasError = issues.some((msg) => msg.includes("Missing") || msg.includes("Need at least one contact"));
    let status = "valid";
    if (issues.length && !hasError) status = "warning";
    if (hasError) status = "error";
    if (issues.some((msg) => msg.includes("Duplicate"))) status = "duplicate";
    return { ...row, issues, status };
  });
}

function getBrowserDevicePayload() {
  if (typeof navigator === "undefined") return {};
  return {
    userAgent: String(navigator.userAgent || "").trim(),
    platform: String(navigator.platform || "").trim(),
    language: String(navigator.language || "").trim()
  };
}

function getCurrentPositionAsync() {
  return new Promise((resolve, reject) => {
    if (typeof navigator === "undefined" || !navigator.geolocation) {
      reject(new Error("Geolocation is not available in this browser."));
      return;
    }
    navigator.geolocation.getCurrentPosition(resolve, reject, {
      enableHighAccuracy: true,
      timeout: 20000,
      maximumAge: 0
    });
  });
}

